  "https://images.unsplash.com/photo-1626071494507-dc79630ccb9c?auto=format&fit=crop&q=80&w=800",
  "https://images.unsplash.com/photo-1501166243542-a7f457193963?auto=format&fit=crop&q=80&w=800",
];

const generateInitialData = (): RiceProduct[] => {
  const base: RiceProduct[] = [
    { id: 'R001', name: '五常稻花香二号', origin: '黑龙江五常', price: 19.8, weight: 5, textureScore: 88, aromaScore: 95, packagingImage: RICE_IMAGE_POOL[0], description: '正宗五常核心产区，米粒细长。' },
    { id: 'R002', name: '泰国茉莉香米', origin: '泰国清莱', price: 12.5, weight: 5, textureScore: 65, aromaScore: 90, packagingImage: RICE_IMAGE_POOL[1], description: '进口一级香米，香味独特。' },
    { id: 'R003', name: '盘锦蟹田米', origin: '辽宁盘锦', price: 7.8, weight: 10, textureScore: 75, aromaScore: 40, packagingImage: RICE_IMAGE_POOL[2], description: '蟹稻共生，米珠圆玉润。' }
  ];
  return base;
};

const INITIAL_USERS: UserProfile[] = [
  { id: 'U001', username: 'admin', password: 'admin123', ip: '127.0.0.1', role: 'Registered', status: 'Active', lastActive: '刚刚', requestCount: 100, favorites: [] }
];

/**
 * 模拟服务器响应延迟
 */
const delay = (ms: number = 600) => new Promise(res => setTimeout(res, ms));

export const MockBackend = {
  // --- 稻米接口 ---
  getInventory: async (): Promise<RiceProduct[]> => {
    await delay();
    const data = localStorage.getItem(DB_KEYS.INVENTORY);
    if (!data) {
      const initial = generateInitialData();
      localStorage.setItem(DB_KEYS.INVENTORY, JSON.stringify(initial));
      return initial;
    }
    return JSON.parse(data);
  },

  saveProduct: async (product: RiceProduct): Promise<RiceProduct> => {
    await delay(800);
    const data = await MockBackend.getInventory();
    const index = data.findIndex(p => p.id === product.id);
    if (index > -1) {
      data[index] = product;
    } else {
      data.push(product);
    }
    localStorage.setItem(DB_KEYS.INVENTORY, JSON.stringify(data));
    return product;
  },

  // --- 用户接口 ---
  getUsers: async (): Promise<UserProfile[]> => {
    await delay();
    const data = localStorage.getItem(DB_KEYS.USERS);
    if (!data) {
      localStorage.setItem(DB_KEYS.USERS, JSON.stringify(INITIAL_USERS));
      return INITIAL_USERS;
    }
    return JSON.parse(data);
  },

  updateUser: async (user: UserProfile): Promise<UserProfile> => {
    await delay(500);
    const users = await MockBackend.getUsers();
    const updated = users.map(u => u.id === user.id ? user : u);
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(updated));
    return user;
  },

  register: async (user: UserProfile): Promise<UserProfile> => {
    await delay(1000);
    const users = await MockBackend.getUsers();
    if (users.some(u => u.username === user.username)) throw new Error("用户名已存在");
    users.push(user);
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));
    return user;
  }
};

import { MockBackend } from './mockBackend';
import { RiceProduct, UserProfile, UserPreferences, RecommendationResponse } from '../types';
import { getRiceRecommendations as callGeminiText, analyzeImageForRice as callGeminiVision } from './geminiService';

/**
 * 后端服务接口封装
 */
export const RiceApi = {
  // 获取所有产品
  fetchProducts: () => MockBackend.getInventory(),

  // 保存/更新产品 (管理员)
  saveProduct: (p: RiceProduct) => MockBackend.saveProduct(p),

  // 获取所有用户 (管理员)
  fetchUsers: () => MockBackend.getUsers(),

  // 更新用户信息 (收藏、状态等)
  syncUser: (u: UserProfile) => MockBackend.updateUser(u),

  // 用户注册
  register: (u: UserProfile) => MockBackend.register(u),

  // AI 推荐接口 (组合后端数据与 Gemini 能力)
  getRecommendations: async (prefs: UserPreferences): Promise<RecommendationResponse> => {
    const inventory = await MockBackend.getInventory();
    return callGeminiText(prefs, inventory);
  },

  analyzeImage: async (base64: string): Promise<RecommendationResponse> => {
    const inventory = await MockBackend.getInventory();
    return callGeminiVision(base64, inventory);
  }
};

