import { GoogleGenAI, Type } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceProduct } from "../../types";

// 只有在此“后端”模块中才初始化 AI Client
// 在 Next.js 中，这里的 process.env.API_KEY 永远不会泄露给浏览器
const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const recommendationSchema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "推荐理由" }
        },
        required: ["id", "matchReason"],
      },
    },
    analysis: { type: Type.STRING },
  },
  required: ["recommendations", "analysis"],
};

/**
 * 模拟 Next.js 后端 Action：处理文本推荐请求
 */
export const handleTextRecommendationRequest = async (prefs: UserPreferences, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const ai = getAIClient();
  const inventoryStr = inventory.map(p => `编号:${p.id}|名称:${p.name}|价格:${p.price}|产地:${p.origin}`).join('\n');

  const prompt = `
    作为稻米专家后端服务，请为用户匹配稻米。
    用户偏好：${JSON.stringify(prefs)}
    库内产品：\n${inventoryStr}
    要求：仅返回匹配产品列表及其理由。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: recommendationSchema,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const recommendations = (parsed.recommendations || [])
    .map((rec: any) => {
      const product = inventory.find(p => p.id === rec.id);
      return product ? { ...product, matchReason: rec.matchReason } : null;
    })
    .filter((item: any) => item !== null);

  return { 
    recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
    analysis: parsed.analysis || "后台匹配完成。" 
  };
};

/**
 * 模拟 Next.js 后端 Action：处理图像识别请求
 */
export const handleImageAnalysisRequest = async (base64Image: string, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const ai = getAIClient();
  const inventoryStr = inventory.map(p => `编号:${p.id}|名称:${p.name}`).join('\n');

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image } },
        { text: `分析图片中食物口味并匹配：\n${inventoryStr}` }
      ]
    },
    config: {
      responseMimeType: "application/json",
      responseSchema: recommendationSchema,
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  const recommendations = (parsed.recommendations || [])
    .map((rec: any) => {
      const product = inventory.find(p => p.id === rec.id);
      return product ? { ...product, matchReason: rec.matchReason } : null;
    })
    .filter((item: any) => item !== null);

  return { 
    recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
    analysis: parsed.analysis || "后台图像分析完成。" 
  };
};

import { MockBackend } from './mockBackend';
import { UserPreferences, RecommendationResponse } from '../types';
// 导入模拟的后端处理器
import { handleTextRecommendationRequest, handleImageAnalysisRequest } from './backend/geminiHandler';

/**
 * 模拟前端 API 请求工具 (类似 axios 或 fetch)
 */
const mockFetch = async <T>(apiAction: () => Promise<T>): Promise<T> => {
  // 模拟网络开销和后端处理延迟
  console.log("%c[Network Request] Sending data to /api/recommend...", "color: #0ea5e9; font-weight: bold;");
  await new Promise(res => setTimeout(res, 800));
  const result = await apiAction();
  console.log("%c[Network Response] 200 OK - Data received from server.", "color: #10b981; font-weight: bold;");
  return result;
};

export const RiceApi = {
  fetchProducts: () => MockBackend.getInventory(),
  saveProduct: (p: any) => MockBackend.saveProduct(p),
  fetchUsers: () => MockBackend.getUsers(),
  syncUser: (u: any) => MockBackend.updateUser(u),
  register: (u: any) => MockBackend.register(u),

  /**
   * AI 推荐接口：前端调用点
   * 注意：这里不再引用 @google/genai，实现了前后端完全解耦。
   */
  getRecommendations: async (prefs: UserPreferences): Promise<RecommendationResponse> => {
    const inventory = await MockBackend.getInventory();
    // 模拟调用 Next.js API Route (/api/recommend)
    return mockFetch(() => handleTextRecommendationRequest(prefs, inventory));
  },

  /**
   * 图像分析接口
   */
  analyzeImage: async (base64: string): Promise<RecommendationResponse> => {
    const inventory = await MockBackend.getInventory();
    // 模拟调用 Next.js API Route (/api/analyze)
    return mockFetch(() => handleImageAnalysisRequest(base64, inventory));
  }
};

