import { GoogleGenAI, Type, Modality } from "@google/genai";
import { UserPreferences, RecommendationResponse, RiceProduct } from "../../types";

const getAIClient = () => new GoogleGenAI({ apiKey: process.env.API_KEY });

const recommendationSchema = {
  type: Type.OBJECT,
  properties: {
    recommendations: {
      type: Type.ARRAY,
      items: {
        type: Type.OBJECT,
        properties: {
          id: { type: Type.STRING },
          matchReason: { type: Type.STRING, description: "推荐理由" }
        },
        required: ["id", "matchReason"],
      },
    },
    analysis: { type: Type.STRING },
  },
  required: ["recommendations", "analysis"],
};

export const handleTextRecommendationRequest = async (prefs: UserPreferences, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const ai = getAIClient();
  const inventoryStr = inventory.map(p => `编号:${p.id}|名称:${p.name}|产地:${p.origin}`).join('\n');

  const prompt = `
    作为稻米专家，请从以下库中匹配最适合的产品。
    偏好：${JSON.stringify(prefs)}
    库：\n${inventoryStr}
    注意：请同时利用 Google 搜索获取这些品种或产地的实时最新动态（如：今年收成、市场价格趋势）。
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: recommendationSchema,
    },
  });

  const parsed = JSON.parse(response.text || "{}");
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = groundingChunks.map((chunk: any) => ({
    title: chunk.web?.title || "相关资讯",
    uri: chunk.web?.uri || "#"
  })).slice(0, 3);

  const recommendations = (parsed.recommendations || [])
    .map((rec: any) => {
      const product = inventory.find(p => p.id === rec.id);
      return product ? { ...product, matchReason: rec.matchReason, groundingSources: sources } : null;
    })
    .filter((item: any) => item !== null);

  return { 
    recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
    analysis: parsed.analysis || "AI 深度匹配完成。" 
  };
};

export const handleImageAnalysisRequest = async (base64Image: string, inventory: RiceProduct[]): Promise<RecommendationResponse> => {
  const ai = getAIClient();
  const inventoryStr = inventory.map(p => `编号:${p.id}|名称:${p.name}`).join('\n');

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: {
      parts: [
        { inlineData: { mimeType: "image/jpeg", data: base64Image } },
        { text: `分析图中食物口味，从库中推荐配米：\n${inventoryStr}` }
      ]
    },
    config: {
      tools: [{ googleSearch: {} }],
      responseMimeType: "application/json",
      responseSchema: recommendationSchema,
    }
  });

  const parsed = JSON.parse(response.text || "{}");
  const groundingChunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks || [];
  const sources = groundingChunks.map((chunk: any) => ({
    title: chunk.web?.title || "菜品知识库",
    uri: chunk.web?.uri || "#"
  })).slice(0, 2);

  const recommendations = (parsed.recommendations || [])
    .map((rec: any) => {
      const product = inventory.find(p => p.id === rec.id);
      return product ? { ...product, matchReason: rec.matchReason, groundingSources: sources } : null;
    })
    .filter((item: any) => item !== null);

  return { 
    recommendations: recommendations.length > 0 ? recommendations : inventory.slice(0, 3), 
    analysis: parsed.analysis || "图像视觉分析完成。" 
  };
};

/**
 * 语音合成后端处理器 (TTS)
 */
export const synthesizeVoiceDescription = async (text: string): Promise<string> => {
  const ai = getAIClient();
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: [{ parts: [{ text: `用亲切温和的导购口吻播报：${text}` }] }],
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          prebuiltVoiceConfig: { voiceName: 'Kore' },
        },
      },
    },
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  return base64Audio || "";
};

