const mockFetch = async <T>(apiAction: () => Promise<T>): Promise<T> => {
  console.log("%c[Network Request] Sending to /api/...", "color: #0ea5e9; font-weight: bold;");
  await new Promise(res => setTimeout(res, 800));
  const result = await apiAction();
  return result;
};

