                <div className="flex justify-between items-start mb-3">
                    <h3 className="text-gray-900 font-bold text-lg leading-tight group-hover:text-emerald-700 transition-colors line-clamp-2">{product.name}</h3>
                    <div className="text-right flex-shrink-0">
                      <span className="text-xl font-bold text-emerald-600">¥{product.price}</span>
                      <div className="text-[10px] text-gray-400">/kg</div>
                    </div>
                </div>
                <div className="flex items-center gap-3 text-[11px] text-gray-400 mb-4">
                    <span className="flex items-center"><MapPin className="w-3.5 h-3.5 mr-1" />{product.origin}</span>
                    <span className="flex items-center"><Package className="w-3.5 h-3.5 mr-1" />{product.weight}kg</span>
                    <span className="flex items-center text-blue-500 font-medium ml-auto"><Droplets className="w-3 h-3 mr-1" />{product.cookingRatio}</span>
                </div>
                <div className="bg-gray-50/50 rounded-xl p-4 mb-5 border border-dashed border-gray-200 flex-1">
                    <p className="text-gray-600 text-xs leading-relaxed line-clamp-4 italic">
                        {product.matchReason || product.description}
                    </p>
                </div>
                <div className="pt-4 border-t border-gray-100 flex items-center justify-end text-xs">
                    <span className="text-emerald-600 font-bold flex items-center gap-1 group-hover:gap-2 transition-all">
                        查看产品详情 <ChevronRight className="w-4 h-4" />
                    </span>
                </div>
            </div>
        </div>
    );
};

const ResultsGrid: React.FC<ResultsGridProps> = ({ products, analysisText, favorites = [], onToggleFavorite, showAnalysis = true }) => {
  const [selectedProduct, setSelectedProduct] = useState<RiceProduct | null>(null);

  const getAccentColor = (index: number) => {
    const accentColors = ['bg-emerald-500', 'bg-sky-500', 'bg-amber-500'];
    return accentColors[index % 3];
  };

  return (
    <div className="space-y-8 pb-12">
      {showAnalysis && analysisText && (
        <div className="bg-white p-6 rounded-2xl border border-emerald-100 shadow-sm relative overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500">
           <div className="absolute top-0 left-0 w-1.5 h-full bg-emerald-500"></div>
           <h3 className="text-sm font-bold text-emerald-800 mb-3 flex items-center gap-2">
              <Sparkles className="w-4 h-4 text-amber-500" /> 智能匹配分析报告
           </h3>
           <p className="text-gray-600 text-sm leading-relaxed">{analysisText}</p>
        </div>
      )}

      {products.length === 0 ? (
        <div className="text-center py-24 bg-white rounded-3xl border-2 border-dashed border-gray-100">
           <ImageIcon className="w-16 h-16 text-gray-100 mx-auto mb-4" />
           <p className="text-gray-400 text-base font-medium">暂时没有找到符合条件的稻米</p>
           <p className="text-gray-300 text-sm mt-1">您可以尝试放宽筛选条件或更换图片再次尝试</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-2 xl:grid-cols-3 gap-8">
          {products.map((product, index) => (
               <ProductCard key={product.id} product={product} index={index} onClick={() => setSelectedProduct(product)} />
          ))}
        </div>
      )}

      {selectedProduct && (
          <ProductDetailModal 
            product={selectedProduct} 
            onClose={() => setSelectedProduct(null)} 
            isFavorite={favorites.includes(selectedProduct.id)}
            onToggleFavorite={onToggleFavorite}
            accentColor={getAccentColor(products.indexOf(selectedProduct))}
          />
      )}
    </div>
  );
};

export default ResultsGrid;

import React, { useState } from 'react';
import { Database, Users, LogOut, Plus, X, Save, Pencil, Search, ShieldAlert, CheckCircle, Ban, UserPlus, Image as ImageIcon, Upload, Activity, Droplets } from 'lucide-react';
import { RiceProduct, UserProfile } from '../types';

interface AdminDashboardProps {
  onLogout: () => void;
  inventory: RiceProduct[];
  onAddProduct: (product: RiceProduct) => void;
  onUpdateProduct: (product: RiceProduct) => void;
  users: UserProfile[];
  onUpdateUsers: (users: UserProfile[]) => void;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, inventory, onAddProduct, onUpdateProduct, users, onUpdateUsers }) => {
  const [activeTab, setActiveTab] = useState<'data' | 'users'>('data');
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [productSearch, setProductSearch] = useState('');

  const [userSearch, setUserSearch] = useState('');
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [userForm, setUserForm] = useState<Partial<UserProfile>>({
    username: '',
    role: 'Registered',
    status: 'Active'
  });

  const [newProduct, setNewProduct] = useState<Partial<RiceProduct>>({
    name: '',
    origin: '',
    price: 0,
    weight: 5,
    textureScore: 50,
    aromaScore: 50,
    cookingRatio: '1:1.2',
    stock: 100,
    status: 'Normal',
    description: '',
    packagingImage: '',
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setNewProduct(prev => ({ 
        ...prev, 
        [name]: ['price', 'stock', 'textureScore', 'aromaScore', 'weight'].includes(name)
            ? Math.max(0, Number(value))
            : value 
    }));
  };

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      const reader = new FileReader();
      reader.onloadend = () => {
        setNewProduct(prev => ({ ...prev, packagingImage: reader.result as string }));
      };
      reader.readAsDataURL(file);
    }
  };

  const openAddModal = () => {
    setEditingId(null);
    setNewProduct({ name: '', origin: '', price: 0, weight: 5, textureScore: 50, aromaScore: 50, cookingRatio: '1:1.2', stock: 100, status: 'Normal', description: '', packagingImage: '' });
    setShowAddModal(true);
  };

  const openEditModal = (product: RiceProduct) => {
    setEditingId(product.id);
    setNewProduct({ ...product });
    setShowAddModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || !newProduct.origin) return;

    if (editingId) {
        const updatedProduct: RiceProduct = {
            ...newProduct as RiceProduct,
            id: editingId,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
        };
        onUpdateProduct(updatedProduct);
    } else {
        const productToAdd: RiceProduct = {
            id: `R${Math.floor(Math.random() * 10000).toString().padStart(3, '0')}`,
            name: newProduct.name!,
            origin: newProduct.origin!,
            price: newProduct.price || 0,
            weight: newProduct.weight || 5,
            textureScore: newProduct.textureScore || 50,
            aromaScore: newProduct.aromaScore || 50,
            cookingRatio: newProduct.cookingRatio || '1:1.2',
            stock: newProduct.stock || 0,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
            description: newProduct.description || '暂无描述',
            matchReason: '',
            tags: [],
            packagingImage: newProduct.packagingImage,
        };
        onAddProduct(productToAdd);
    }

    setShowAddModal(false);
  };

  const handleUserInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setUserForm(prev => ({ ...prev, [name]: value }));
  };

