          <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center">
            <Store className="text-white w-5 h-5" />
          </div>
          <div>
            <h1 className="font-bold text-gray-900 text-lg">稻米系统 <span className="text-xs font-normal text-white bg-blue-600 px-2 py-0.5 rounded-full ml-1">商家中心</span></h1>
            <p className="text-[10px] text-gray-400">商品发布与库存管理系统</p>
          </div>
        </div>
        <button onClick={onLogout} className="text-sm text-gray-500 hover:text-red-600 flex items-center gap-2 transition-colors">
          <LogOut className="w-4 h-4" />
          退出商家系统
        </button>
      </header>

      <div className="flex flex-1 overflow-hidden">
        <aside className="w-64 bg-white border-r border-gray-200 flex-shrink-0 hidden md:block">
          <nav className="p-4 space-y-1">
            <button
              onClick={() => setActiveTab('data')}
              className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${activeTab === 'data' ? 'bg-blue-50 text-blue-700' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Database className="w-4 h-4" />
              库存品种管理
            </button>
            <button
              onClick={() => setActiveTab('users')}
              className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${activeTab === 'users' ? 'bg-blue-50 text-blue-700' : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Users className="w-4 h-4" />
              平台用户概览
            </button>
