            >
              <Database className="w-4 h-4" />
              {isAdmin ? '全局库存概览' : '我的库存管理'}
            </button>
            <button
              onClick={() => setActiveTab('users')}
              className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${activeTab === 'users' ? (isAdmin ? 'bg-indigo-50 text-indigo-700' : 'bg-blue-50 text-blue-700') : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Users className="w-4 h-4" />
              {isAdmin ? '全平台用户管理' : '平台用户概览'}
            </button>
          </nav>
        </aside>

        <main className="flex-1 overflow-y-auto p-6 md:p-8">
          {activeTab === 'data' && (
            <div className="space-y-6 animate-in fade-in duration-300">
               <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                 <div>
                    <h2 className="text-xl font-bold text-gray-900 mb-1">{isAdmin ? '全量库存数据库' : '稻米库存库'}</h2>
                    <p className="text-sm text-gray-500">管理{isAdmin ? '全平台' : '您的'}上架商品，当前显示 {filteredInventory.length} / 总计 {inventory.length} 条</p>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64">
                        <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                        <input
                            type="text"
                            placeholder="快速检索商品..."
                            value={productSearch}
                            onChange={(e) => setProductSearch(e.target.value)}
                            className={`w-full bg-white border border-gray-200 rounded-lg pl-10 pr-4 py-2 text-sm focus:ring-2 ${isAdmin ? 'focus:ring-indigo-500 focus:border-indigo-500' : 'focus:ring-blue-500 focus:border-blue-500'}`}
                        />
