                              <Save className="w-4 h-4" />
                              确认提交
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

export default AdminDashboard;

import React, { useState, useEffect } from 'react';
import { UserPreferences, RecommendationResponse, UserRole, RiceProduct, UserProfile } from './types.ts';
import { RiceApi } from './services/apiService.ts';
import Hero from './components/Hero.tsx';
import PreferenceForm from './components/PreferenceForm.tsx';
import ResultsGrid from './components/ResultsGrid.tsx';
import AnalysisChart from './components/AnalysisChart.tsx';
import Login from './components/Login.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import UserAuthModal from './components/UserAuthModal.tsx';
import { RotateCcw, LogOut, Heart, Search, LogIn, Loader2 } from 'lucide-react';

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>(null);
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [inventory, setInventory] = useState<RiceProduct[]>([]);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isDataFetching, setIsDataFetching] = useState(true);
  const [results, setResults] = useState<RecommendationResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authConfig, setAuthConfig] = useState<{mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin'}>({mode: 'login', role: 'User'});
  const [viewMode, setViewMode] = useState<'search' | 'favorites'>('search');

  useEffect(() => {
    const initApp = async () => {
      try {
        const [products, allUsers] = await Promise.all([
          RiceApi.fetchProducts(),
          RiceApi.fetchUsers()
        ]);
        setInventory(products);
        setUsers(allUsers);
      } catch (err) {
        setError("无法连接到系统服务，请稍后重试。");
      } finally {
        setIsDataFetching(false);
      }
    };
    initApp();
  }, []);

  const handleLoginPortal = (role: UserRole) => {
    setUserRole(role);
    setResults(null); 
    setViewMode('search');
    if (role === 'merchant' || role === 'admin') setCurrentUser(null);
  };

  const handleOpenAuth = (mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin') => {
      setAuthConfig({ mode, role });
      setShowAuthModal(true);
  };

  const handleLogout = () => {
    setUserRole(null);
    setResults(null);
    setCurrentUser(null);
    setViewMode('search');
  };

  const handleAddProduct = async (newProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(newProduct);
    setInventory(prev => [...prev.filter(p => p.id !== saved.id), saved]);
  };

  const handleUpdateProduct = async (updatedProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(updatedProduct);
    setInventory(prev => prev.map(p => p.id === saved.id ? saved : p));
  };

  const handleUpdateUsers = (updatedUsers: UserProfile[]) => {
      setUsers(updatedUsers);
  };

  const handleClientRegister = async (username: string, password?: string, role: 'User' | 'Merchant' | 'Admin' = 'User') => {
    const newUser: UserProfile = {
      id: `${role === 'Merchant' ? 'M' : role === 'Admin' ? 'A' : 'U'}${Date.now()}`,
      username,
      password, 
      role,
      status: 'Active',
      ip: '127.0.0.1', 
      lastActive: '刚刚',
      requestCount: 0,
      favorites: []
    };
    const registered = await RiceApi.register(newUser);
    setUsers(prev => [registered, ...prev]);
    setCurrentUser(registered);
    setUserRole(role === 'Merchant' ? 'merchant' : role === 'Admin' ? 'admin' : 'user');
  };

  const handleClientLogin = async (username: string, password?: string) => {
    const user = users.find(u => u.username === username && u.password === password);

    if (!user) {
      throw new Error("账号或密码错误");
    }

    if (user.status !== 'Active') {
      throw new Error("您的账号已被锁定，请联系系统总管理员。");
    }

    const updatedUser = { ...user, lastActive: '刚刚' };
    setCurrentUser(updatedUser);
    setUserRole(user.role === 'Merchant' ? 'merchant' : user.role === 'Admin' ? 'admin' : 'user');

    setUsers(prev => prev.map(u => u.id === user.id ? updatedUser : u));
    await RiceApi.syncUser(updatedUser);
  };

  const toggleFavorite = async (productId: string) => {
    if (!currentUser) {
      handleOpenAuth('login', 'User');
      return;
    }

    const isFav = currentUser.favorites.includes(productId);
    const updatedUser = {
        ...currentUser,
        favorites: isFav ? currentUser.favorites.filter(id => id !== productId) : [...currentUser.favorites, productId]
    };

    setCurrentUser(updatedUser);
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    await RiceApi.syncUser(updatedUser);
  };

  const handlePreferenceSubmit = async (prefs: UserPreferences) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.getRecommendations(prefs);
      setResults(data);
    } catch (err) {
      setError("服务请求超时，请重新提交匹配。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSubmit = async (base64: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.analyzeImage(base64);
      setResults(data);
    } catch (err) {
      setError("识别服务暂时不可用。");
    } finally {
      setIsLoading(false);
    }
  }

  const reset = () => {
    setResults(null);
    setViewMode('search');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  if (isDataFetching) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 text-gray-400">
        <Loader2 className="w-10 h-10 animate-spin text-emerald-500 mb-4" />
        <p className="text-sm font-medium animate-pulse">正在加载系统数据...</p>
      </div>
    );
  }

  if (!userRole) {
    return <Login onLogin={handleLoginPortal} onOpenAuth={handleOpenAuth} />;
  }

  if (userRole === 'merchant' || userRole === 'admin') {
    return (
      <AdminDashboard 
        onLogout={handleLogout} 
        inventory={inventory}
        onAddProduct={handleAddProduct}
        onUpdateProduct={handleUpdateProduct}
        users={users}
        onUpdateUsers={handleUpdateUsers}
        currentUser={currentUser}
      />
    );
  }

  const favoriteProducts = currentUser 
    ? inventory.filter(p => currentUser.favorites.includes(p.id))
    : [];

  return (
    <div className="min-h-screen bg-[#fafafa] text-gray-900 font-sans selection:bg-emerald-100 relative">
      <nav className="fixed top-0 left-0 w-full p-4 flex justify-between items-center z-[80] bg-white/60 backdrop-blur-md border-b border-gray-100 shadow-sm">
          <div className="flex items-center gap-3">
             {!currentUser ? (
               <button onClick={() => handleOpenAuth('login', 'User')} className="flex items-center gap-2 bg-emerald-600 shadow-md shadow-emerald-200 px-5 py-2 rounded-full text-sm font-bold text-white hover:bg-emerald-700 transition-all active:scale-95">
                 <LogIn className="w-4 h-4" /> 登录 / 注册
               </button>
             ) : (
                <div className="flex items-center gap-2">
                   <div className="flex items-center gap-2 bg-gray-100 px-4 py-2 rounded-full text-xs font-bold text-gray-700">
                      <div className="w-5 h-5 bg-emerald-500 text-white rounded-full flex items-center justify-center text-[10px]">
                        {currentUser.username.charAt(0).toUpperCase()}
                      </div>
                      你好，{currentUser.username}
                   </div>
                   <button 
                      onClick={() => setViewMode(viewMode === 'search' ? 'favorites' : 'search')}
                      className={`flex items-center gap-2 px-4 py-2 rounded-full text-xs font-bold transition-all shadow-sm border ${viewMode === 'favorites' ? 'bg-red-500 text-white border-red-500 shadow-red-200' : 'bg-white text-gray-600 border-gray-200 hover:text-red-500'}`}
                   >
                      <Heart className={`w-3.5 h-3.5 ${viewMode === 'favorites' ? 'fill-current' : ''}`} />
                      收藏夹 ({currentUser.favorites.length})
                   </button>
                </div>
             )}
          </div>
          <button onClick={handleLogout} className="text-[10px] text-gray-400 hover:text-red-500 flex items-center gap-1 transition-colors px-3 py-2 rounded-lg hover:bg-red-50 font-bold">
              <LogOut className="w-3 h-3" /> 退出系统
          </button>
      </nav>

      <div className="w-full max-w-[1600px] mx-auto px-4 md:px-8 pt-24 pb-12">
        {viewMode === 'favorites' && currentUser ? (
           <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
              <div className="flex items-center justify-between mb-8">
                 <h2 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
                    <Heart className="w-8 h-8 text-red-500 fill-red-500" /> 我的收藏夹
                 </h2>
                 <button onClick={() => setViewMode('search')} className="text-sm font-bold text-emerald-600 hover:text-emerald-700 underline underline-offset-4">
                    返回搜索推荐
                 </button>
              </div>
              <ResultsGrid products={favoriteProducts} analysisText="" favorites={currentUser.favorites} onToggleFavorite={toggleFavorite} showAnalysis={false} />
           </div>
        ) : (
          <>
            <div className={`transition-all duration-700 ${results ? 'mb-12' : 'flex flex-col items-center justify-center min-h-[70vh]'}`}>
                <div className="w-full max-w-3xl mx-auto">
                    <Hero />
                    {!results && (
                        <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 w-full">
                            <PreferenceForm onSubmitPreferences={handlePreferenceSubmit} onSubmitImage={handleImageSubmit} isLoading={isLoading} />
                        </div>
                    )}
                </div>
            </div>

            {results && (
                <div className="w-full animate-in fade-in slide-in-from-bottom-12 duration-1000 space-y-8">
                    <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white/40 backdrop-blur p-4 rounded-3xl border border-white/50 shadow-sm">
                        <div className="flex flex-col">
                           <h2 className="text-2xl font-black text-gray-900 flex items-center gap-3">
                              <Search className="w-7 h-7 text-emerald-600" /> 推荐结果
                           </h2>
                        </div>
                        <button onClick={reset} className="flex items-center justify-center gap-2 text-sm font-bold text-gray-500 hover:text-emerald-600 transition-all px-6 py-2.5 rounded-full hover:bg-white bg-gray-50/50 shadow-sm border border-transparent hover:border-emerald-100">
                            <RotateCcw className="w-4 h-4" /> 重新匹配
                        </button>
                    </div>

                    <div className="grid grid-cols-1 gap-8">
                       <AnalysisChart products={results.recommendations} />
                       <ResultsGrid products={results.recommendations} analysisText={results.analysis} favorites={currentUser?.favorites || []} onToggleFavorite={toggleFavorite} />
                    </div>
                </div>
            )}

            {error && (
              <div className="max-w-md mx-auto mt-8 p-4 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-sm font-medium flex items-center gap-3">
                 <div className="w-2 h-2 bg-red-500 rounded-full animate-ping"></div>
                 {error}
              </div>
            )}
          </>
        )}
      </div>

      {showAuthModal && (
        <UserAuthModal 
            initialMode={authConfig.mode}
            initialRole={authConfig.role}
            onClose={() => setShowAuthModal(false)} 
            onLogin={handleClientLogin} 
            onRegister={handleClientRegister} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { X, UserPlus, LogIn, AlertCircle, Loader2 } from 'lucide-react';

interface UserAuthModalProps {
  initialMode?: 'login' | 'register';
  initialRole: 'User' | 'Merchant' | 'Admin';
  onClose: () => void;
  onLogin: (username: string, password?: string) => Promise<void>;
  onRegister: (username: string, password?: string, role?: 'User' | 'Merchant' | 'Admin') => Promise<void>;
}

const UserAuthModal: React.FC<UserAuthModalProps> = ({ initialMode = 'login', initialRole, onClose, onLogin, onRegister }) => {
  const [mode, setMode] = useState<'login' | 'register'>(initialMode);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!username || !password) {
      setError("请输入完整的账号和密码");
      return;
    }

    setError('');
    setIsSubmitting(true);
    try {
      if (mode === 'login') {
        await onLogin(username, password);
      } else {
        await onRegister(username, password, initialRole);
      }
      onClose();
    } catch (err: any) {
      console.error("Auth Error:", err);
      setError(err.message || "过程中发生未知错误，请检查账号密码");
    } finally {
      setIsSubmitting(false);
    }
  };

  const getRoleLabel = () => {
      switch(initialRole) {
          case 'Admin': return '管理总台';
          case 'Merchant': return '商家版';
          default: return '普通用户';
      }
  };

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300">
        <div className={`px-6 py-5 border-b border-gray-100 flex justify-between items-center ${initialRole === 'Admin' ? 'bg-indigo-50/30' : 'bg-emerald-50/30'}`}>
          <div className="flex flex-col">
            <h3 className="font-bold text-gray-900 leading-tight">
              {mode === 'login' ? '账户登录' : '新账户注册'}
            </h3>
            <span className={`text-[10px] font-bold uppercase tracking-widest mt-0.5 ${initialRole === 'Admin' ? 'text-indigo-600' : 'text-emerald-600'}`}>
                {getRoleLabel()}
            </span>
          </div>
          <button onClick={onClose} className="p-1 text-gray-400 hover:text-gray-600 transition-colors bg-white/50 rounded-full">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-5">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">用户名</label>
            <input
              type="text"
              disabled={isSubmitting}
              value={username}
              onChange={(e) => { setUsername(e.target.value); setError(''); }}
              className={`w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm transition-all placeholder-gray-300 disabled:opacity-50 ${initialRole === 'Admin' ? 'focus:ring-2 focus:ring-indigo-500' : 'focus:ring-2 focus:ring-emerald-500'}`}
              placeholder="请输入您的账号"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">账户密码</label>
            <input
              type="password"
              disabled={isSubmitting}
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              className={`w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm transition-all placeholder-gray-300 disabled:opacity-50 ${initialRole === 'Admin' ? 'focus:ring-2 focus:ring-indigo-500' : 'focus:ring-2 focus:ring-emerald-500'}`}
              placeholder="请输入您的密码"
            />
          </div>

          {error && (
            <div className="flex items-center gap-2 text-xs text-red-600 bg-red-50 p-3.5 rounded-xl border border-red-100 animate-in shake duration-300">
              <AlertCircle className="w-4 h-4 flex-shrink-0" />
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className={`w-full text-white py-4 rounded-2xl font-bold transition-all flex justify-center items-center gap-2 shadow-xl active:scale-95 disabled:opacity-70 ${initialRole === 'Admin' ? 'bg-indigo-600 hover:bg-indigo-700 shadow-indigo-200' : 'bg-emerald-600 hover:bg-emerald-700 shadow-emerald-200'}`}
          >
            {isSubmitting ? (
              <Loader2 className="w-5 h-5 animate-spin" />
            ) : mode === 'login' ? (
              <>
                <LogIn className="w-4 h-4" /> 确认登录
              </>
            ) : (
              <>
                <UserPlus className="w-4 h-4" /> 立即注册
              </>
            )}
          </button>

          {initialRole !== 'Admin' && (
              <div className="text-center pt-2">
                <button
                  type="button"
                  disabled={isSubmitting}
                  onClick={() => {
                    setMode(mode === 'login' ? 'register' : 'login');
                    setError('');
                  }}
                  className={`text-xs font-bold transition-colors disabled:opacity-50 ${initialRole === 'Admin' ? 'text-indigo-600 hover:text-indigo-700' : 'text-emerald-600 hover:text-emerald-700'}`}
                >
                  {mode === 'login' ? '还没有账号？前往注册' : '已有账号？前往登录'}
                </button>
              </div>
          )}
        </form>
      </div>
    </div>
  );
};

