  "https://images.unsplash.com/photo-1501166243542-a7f457193963?auto=format&fit=crop&q=80&w=800",
];

const PROVINCES = ['黑龙江', '吉林', '辽宁', '江苏', '浙江', '安徽', '湖北', '湖南', '江西', '广东', '广西', '泰国', '日本', '越南'];
const RICE_VARIANTS = ['稻花香', '长粒香', '丝苗米', '越光米', '蟹田米', '珍珠米', '小农占', '茉莉香米', '秋田小町', '玄米', '胚芽米'];
const BRANDS = ['金龙鱼', '福临门', '北大荒', '十月稻田', '柴火大院', '华润五丰', '恒大兴安', '燕之坊'];

const generateInitialData = (): RiceProduct[] => {
  const data: RiceProduct[] = [];
  for (let i = 1; i <= 100; i++) {
    const id = `R${i.toString().padStart(3, '0')}`;
    const province = PROVINCES[Math.floor(Math.random() * PROVINCES.length)];
    const variant = RICE_VARIANTS[Math.floor(Math.random() * RICE_VARIANTS.length)];
    const brand = BRANDS[Math.floor(Math.random() * BRANDS.length)];
    const price = Number((Math.random() * 45 + 5).toFixed(1));
    const weight = [1, 2.5, 5, 10][Math.floor(Math.random() * 4)];
    const textureScore = Math.floor(Math.random() * 70 + 30);
    const aromaScore = Math.floor(Math.random() * 70 + 30);
    const stock = Math.floor(Math.random() * 2000);

    const ownerId = i <= 50 ? 'M001' : `M${Math.floor(Math.random() * 5 + 2).toString().padStart(3, '0')}`;

    let cookingRatio = "1:1.2";
    if (variant === '玄米' || variant === '胚芽米') {
      cookingRatio = "1:1.8";
    } else if (variant === '丝苗米' || variant === '长粒香') {
      cookingRatio = "1:1.4";
    } else if (textureScore > 80) {
      cookingRatio = "1:1.1";
    }

    let status: 'Normal' | 'Low Stock' | 'Critical' = 'Normal';
    if (stock < 100) status = 'Critical';
    else if (stock < 500) status = 'Low Stock';

    const mainImg = RICE_IMAGE_POOL[i % RICE_IMAGE_POOL.length];

    data.push({
      id,
      ownerId,
      name: `${brand}${province}${variant}`,
      origin: `${province}核心产区`,
      price,
      weight,
      textureScore,
      aromaScore,
      cookingRatio,
      packagingImage: mainImg,
      images: [mainImg, RICE_IMAGE_POOL[(i + 1) % RICE_IMAGE_POOL.length]], // 初始数据模拟两张图
      purchaseUrl: `https://item.jd.com/${Math.floor(Math.random() * 10000000)}.html`, // 模拟京东链接
      description: `精选来自${province}的${variant}，采用物理去壳工艺。口感${textureScore > 70 ? '软糯' : '清爽'}，最佳建议烹饪比例为米水比 ${cookingRatio}。`,
      tags: [variant, province, price > 30 ? '高端礼赠' : '大众消费', '新米上市'],
      stock,
      status,
      matchReason: ''
    });
  }
  return data;
};

const INITIAL_USERS: UserProfile[] = [
  { id: 'A001', username: 'admin', password: 'admin123', ip: '127.0.0.1', role: 'Admin', status: 'Active', lastActive: '刚刚', requestCount: 0, favorites: [] },
  { id: 'M001', username: 'merchant', password: 'password123', ip: '127.0.0.1', role: 'Merchant', status: 'Active', lastActive: '刚刚', requestCount: 0, favorites: [] }
];

const delay = (ms: number = 600) => new Promise(res => setTimeout(res, ms));

export const MockBackend = {
  getInventory: async (): Promise<RiceProduct[]> => {
    await delay();
    const data = localStorage.getItem(DB_KEYS.INVENTORY);
    if (!data) {
      const initial = generateInitialData();
      localStorage.setItem(DB_KEYS.INVENTORY, JSON.stringify(initial));
      return initial;
    }
    return JSON.parse(data);
  },

  getUsers: async (): Promise<UserProfile[]> => {
    await delay();
    const data = localStorage.getItem(DB_KEYS.USERS);
    let users: UserProfile[] = data ? JSON.parse(data) : [...INITIAL_USERS];

    INITIAL_USERS.forEach(initialUser => {
      if (!users.some(u => u.username === initialUser.username)) {
        users.push(initialUser);
      }
    });

    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));
    return users;
  },

  saveProduct: async (product: RiceProduct): Promise<RiceProduct> => {
    await delay(800);
    const data = await MockBackend.getInventory();
    const index = data.findIndex(p => p.id === product.id);
    if (index > -1) {
      data[index] = product;
    } else {
      data.push(product);
    }
    localStorage.setItem(DB_KEYS.INVENTORY, JSON.stringify(data));
    return product;
  },

  updateUser: async (user: UserProfile): Promise<UserProfile> => {
    await delay(500);
    const users = await MockBackend.getUsers();
    const updated = users.map(u => u.id === user.id ? user : u);
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(updated));
    return user;
  },

  register: async (user: UserProfile): Promise<UserProfile> => {
    await delay(1000);
    const users = await MockBackend.getUsers();
    if (users.some(u => u.username === user.username)) throw new Error("用户名已存在");
    users.push(user);
    localStorage.setItem(DB_KEYS.USERS, JSON.stringify(users));
    return user;
  }
};

import React, { useState } from 'react';
import { Database, Users, LogOut, Plus, X, Save, Pencil, Search, ShieldAlert, CheckCircle, Ban, UserPlus, Image as ImageIcon, Store, Activity, Droplets, ShieldCheck, UserCircle, Link, Trash2, Upload } from 'lucide-react';
import { RiceProduct, UserProfile } from '../types.ts';

interface AdminDashboardProps {
  onLogout: () => void;
  inventory: RiceProduct[];
  onAddProduct: (product: RiceProduct) => void;
  onUpdateProduct: (product: RiceProduct) => void;
  users: UserProfile[];
  onUpdateUsers: (users: UserProfile[]) => void;
  currentUser: UserProfile | null;
}

const AdminDashboard: React.FC<AdminDashboardProps> = ({ onLogout, inventory, onAddProduct, onUpdateProduct, users, onUpdateUsers, currentUser }) => {
  const [activeTab, setActiveTab] = useState<'data' | 'users'>('data');
  const [showAddModal, setShowAddModal] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [productSearch, setProductSearch] = useState('');

  const [userSearch, setUserSearch] = useState('');
  const [showUserModal, setShowUserModal] = useState(false);
  const [editingUserId, setEditingUserId] = useState<string | null>(null);
  const [userForm, setUserForm] = useState<Partial<UserProfile>>({
    username: '',
    role: 'User',
    status: 'Active'
  });

  const isAdmin = currentUser?.role === 'Admin';

  const myInventory = isAdmin 
    ? inventory 
    : inventory.filter(p => p.ownerId === currentUser?.id);

  const [newProduct, setNewProduct] = useState<Partial<RiceProduct>>({
    name: '',
    origin: '',
    price: 0,
    weight: 5,
    textureScore: 50,
    aromaScore: 50,
    cookingRatio: '1:1.2',
    stock: 100,
    status: 'Normal',
    description: '',
    purchaseUrl: '',
    images: []
  });

  const handleInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement | HTMLTextAreaElement>) => {
    const { name, value } = e.target;
    setNewProduct(prev => ({ 
        ...prev, 
        [name]: ['price', 'stock', 'textureScore', 'aromaScore', 'weight'].includes(name)
            ? Math.max(0, Number(value))
            : value 
    }));
  };

  const handleMultipleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const files = e.target.files;
    if (files) {
      Array.from(files).forEach(file => {
        const reader = new FileReader();
        reader.onloadend = () => {
          setNewProduct(prev => ({
            ...prev,
            images: [...(prev.images || []), reader.result as string]
          }));
        };
        reader.readAsDataURL(file);
      });
    }
  };

  const removeImage = (index: number) => {
    setNewProduct(prev => ({
      ...prev,
      images: (prev.images || []).filter((_, i) => i !== index)
    }));
  };

  const openAddModal = () => {
    setEditingId(null);
    setNewProduct({ name: '', origin: '', price: 0, weight: 5, textureScore: 50, aromaScore: 50, cookingRatio: '1:1.2', stock: 100, status: 'Normal', description: '', purchaseUrl: '', images: [] });
    setShowAddModal(true);
  };

  const openEditModal = (product: RiceProduct) => {
    setEditingId(product.id);
    setNewProduct({ ...product, images: product.images || (product.packagingImage ? [product.packagingImage] : []) });
    setShowAddModal(true);
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!newProduct.name || !newProduct.origin) return;

    const finalImages = newProduct.images || [];
    const mainImg = finalImages.length > 0 ? finalImages[0] : '';

    if (editingId) {
        const updatedProduct: RiceProduct = {
            ...newProduct as RiceProduct,
            id: editingId,
            ownerId: currentUser?.id,
            packagingImage: mainImg,
            images: finalImages,
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
        };
        onUpdateProduct(updatedProduct);
    } else {
        const productToAdd: RiceProduct = {
            id: `R${Math.floor(Math.random() * 10000).toString().padStart(3, '0')}`,
            ownerId: currentUser?.id,
            name: newProduct.name!,
            origin: newProduct.origin!,
            price: newProduct.price || 0,
            weight: newProduct.weight || 5,
            textureScore: newProduct.textureScore || 50,
            aromaScore: newProduct.aromaScore || 50,
            cookingRatio: newProduct.cookingRatio || '1:1.2',
            stock: newProduct.stock || 0,
            packagingImage: mainImg,
            images: finalImages,
            purchaseUrl: newProduct.purchaseUrl || '',
            status: (newProduct.stock || 0) < 100 ? 'Critical' : (newProduct.stock || 0) < 500 ? 'Low Stock' : 'Normal',
            description: newProduct.description || '暂无描述',
            matchReason: '',
            tags: []
        };
        onAddProduct(productToAdd);
    }

    setShowAddModal(false);
  };

  const handleUserInputChange = (e: React.ChangeEvent<HTMLInputElement | HTMLSelectElement>) => {
    const { name, value } = e.target;
    setUserForm(prev => ({ ...prev, [name]: value }));
  };

  const openAddUserModal = () => {
    setEditingUserId(null);
    setUserForm({ username: '', role: 'User', status: 'Active' });
    setShowUserModal(true);
  };

  const openEditUserModal = (user: UserProfile) => {
    setEditingUserId(user.id);
    setUserForm({ username: user.username, role: user.role, status: user.status });
    setShowUserModal(true);
  };

  const handleUserSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!userForm.username) return;

    if (editingUserId) {
        onUpdateUsers(users.map(u => u.id === editingUserId ? { ...u, ...userForm } as UserProfile : u));
    } else {
        const newUser: UserProfile = {
            id: `U${Math.floor(Math.random() * 10000)}`,
            username: userForm.username!,
            role: userForm.role as 'User' | 'Merchant' | 'Admin',
            status: userForm.status as 'Active' | 'Banned',
            ip: `192.168.1.${Math.floor(Math.random() * 255)}`,
            lastActive: '刚刚',
            requestCount: 0,
            favorites: []
        };
        onUpdateUsers([newUser, ...users]);
    }
    setShowUserModal(false);
  };

  const toggleUserStatus = (userId: string) => {
      onUpdateUsers(users.map(user => {
          if (user.id === userId) {
              return { ...user, status: user.status === 'Active' ? 'Banned' : 'Active' };
          }
          return user;
      }));
  };

  const filteredUsers = users.filter(u => 
    u.username.toLowerCase().includes(userSearch.toLowerCase()) || 
    u.id.toLowerCase().includes(userSearch.toLowerCase())
  );

  const filteredInventory = myInventory.filter(item => 
    item.name.toLowerCase().includes(productSearch.toLowerCase()) || 
    item.origin.toLowerCase().includes(productSearch.toLowerCase()) ||
    item.id.toLowerCase().includes(productSearch.toLowerCase())
  );

  const getStatusLabel = (status?: string) => {
    switch(status) {
      case 'Critical': return '极低';
      case 'Low Stock': return '低库存';
      default: return '充足';
    }
  };

  const getMerchantName = (ownerId?: string) => {
    if (!ownerId) return '系统直营';
    const merchant = users.find(u => u.id === ownerId);
    return merchant ? merchant.username : '未知商家';
  };

  return (
    <div className="min-h-screen bg-gray-50 flex flex-col relative">
      <header className="bg-white border-b border-gray-200 px-6 py-4 flex justify-between items-center sticky top-0 z-10">
        <div className="flex items-center gap-3">
          <div className={`w-8 h-8 rounded-lg flex items-center justify-center ${isAdmin ? 'bg-amber-500' : 'bg-blue-600'}`}>
            {isAdmin ? <ShieldCheck className="text-white w-5 h-5" /> : <Store className="text-white w-5 h-5" />}
          </div>
          <div>
            <h1 className="font-bold text-gray-900 text-lg">稻米系统 <span className={`text-xs font-normal text-white px-2 py-0.5 rounded-full ml-1 ${isAdmin ? 'bg-amber-500' : 'bg-blue-600'}`}>{isAdmin ? '系统总控' : '商家中心'}</span></h1>
            <p className="text-[10px] text-gray-400">{isAdmin ? '全局权限与用户管理中心' : '商品发布与库存管理系统'}</p>
          </div>
        </div>
        <button onClick={onLogout} className="text-sm text-gray-500 hover:text-red-600 flex items-center gap-2 transition-colors">
          <LogOut className="w-4 h-4" />
          退出管理系统
        </button>
      </header>

      <div className="flex flex-1 overflow-hidden">
        <aside className="w-64 bg-white border-r border-gray-200 flex-shrink-0 hidden md:block">
          <nav className="p-4 space-y-1">
            <button
              onClick={() => setActiveTab('data')}
              className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${activeTab === 'data' ? (isAdmin ? 'bg-amber-50 text-amber-700' : 'bg-blue-50 text-blue-700') : 'text-gray-600 hover:bg-gray-50'}`}
            >
              <Database className="w-4 h-4" />
              {isAdmin ? '全局库存概览' : '我的库存管理'}
            </button>
            {isAdmin && (
              <button
                onClick={() => setActiveTab('users')}
                className={`w-full flex items-center gap-3 px-4 py-3 text-sm font-medium rounded-xl transition-all ${activeTab === 'users' ? 'bg-amber-50 text-amber-700' : 'text-gray-600 hover:bg-gray-50'}`}
              >
                <Users className="w-4 h-4" />
                全平台用户管理
              </button>
            )}
          </nav>
        </aside>

        <main className="flex-1 overflow-y-auto p-6 md:p-8">
          {activeTab === 'data' && (
            <div className="space-y-6 animate-in fade-in duration-300">
               <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
                 <div>
                    <h2 className="text-xl font-bold text-gray-900 mb-1">{isAdmin ? '全量库存数据库' : '我的稻米库'}</h2>
                    <p className="text-sm text-gray-500">管理{isAdmin ? '全平台' : '您的'}上架商品，当前显示 {filteredInventory.length} / 总计 {myInventory.length} 条</p>
                 </div>

                 <div className="flex flex-col sm:flex-row gap-3 w-full md:w-auto">
                    <div className="relative flex-1 md:w-64">
                        <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                        <input
                            type="text"
                            placeholder="快速检索商品..."
                            value={productSearch}
                            onChange={(e) => setProductSearch(e.target.value)}
                            className={`w-full bg-white border border-gray-200 rounded-lg pl-10 pr-4 py-2 text-sm focus:ring-2 ${isAdmin ? 'focus:ring-amber-500 focus:border-amber-500' : 'focus:ring-blue-500 focus:border-blue-500'}`}
                        />
                    </div>
                    {!isAdmin && (
                        <button 
                            onClick={openAddModal}
                            className="bg-blue-600 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-blue-700 transition-colors flex items-center justify-center gap-2 whitespace-nowrap"
                        >
                            <Plus className="w-4 h-4" />
                            发布新稻米
                        </button>
                    )}
                 </div>
               </div>

               <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
                  <table className="w-full text-sm text-left">
                    <thead className="bg-gray-50 text-gray-500 font-medium">
                      <tr>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">SKU</th>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">展示图</th>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">商品名称</th>
                        {isAdmin && <th className="px-6 py-4 text-[11px] uppercase tracking-wider">商家来源</th>}
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">单价/水比</th>
                        <th className="px-6 py-4 text-[11px] uppercase tracking-wider">库存状态</th>
                        {!isAdmin && <th className="px-6 py-4 text-right">操作</th>}
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-gray-100">
                      {filteredInventory.map(rice => (
                          <tr key={rice.id} className="hover:bg-gray-50 transition-colors">
                          <td className="px-6 py-4 font-mono text-[10px] text-gray-400">{rice.id}</td>
                          <td className="px-6 py-4">
                              {(rice.images && rice.images.length > 0) || rice.packagingImage ? (
                                <img src={rice.images?.[0] || rice.packagingImage} alt="外观" className="w-10 h-10 object-cover rounded-md border border-gray-100 shadow-sm" />
                              ) : (
                                <div className="w-10 h-10 bg-gray-100 rounded-md flex items-center justify-center text-gray-300">
                                    <ImageIcon className="w-4 h-4" />
                                </div>
                              )}
                          </td>
                          <td className="px-6 py-4 font-medium text-gray-900">
                              <div className="text-sm">{rice.name}</div>
                              <div className="text-[10px] text-gray-400">{rice.origin}</div>
                          </td>
                          {isAdmin && (
                            <td className="px-6 py-4">
                               <div className="flex items-center gap-2">
                                  <UserCircle className="w-3.5 h-3.5 text-amber-500" />
                                  <span className="text-xs font-semibold text-gray-600">{getMerchantName(rice.ownerId)}</span>
                               </div>
                            </td>
                          )}
                          <td className="px-6 py-4 text-gray-600">
                              <div className={`font-bold text-sm ${isAdmin ? 'text-amber-600' : 'text-blue-600'}`}>{rice.cookingRatio}</div>
                              <div className="text-[10px] text-gray-400">{rice.weight}kg/¥{rice.price}</div>
                          </td>
                          <td className="px-6 py-4">
                              <span className={`inline-flex items-center px-2 py-1 rounded-full text-[10px] font-bold ${
                                rice.status === 'Critical' ? 'bg-red-50 text-red-700' :
                                rice.status === 'Low Stock' ? 'bg-amber-50 text-amber-700' :
                                'bg-green-50 text-green-700'
                              }`}>
                                {rice.stock} ({getStatusLabel(rice.status)})
                              </span>
                          </td>
                          {!isAdmin && (
                            <td className="px-6 py-4 text-right">
                                <button 
                                    onClick={() => openEditModal(rice)}
                                    className="text-gray-400 hover:text-blue-600 transition-colors p-1"
                                >
                                    <Pencil className="w-4 h-4" />
                                </button>
                            </td>
                          )}
                          </tr>
                      ))}
                    </tbody>
                  </table>
                  {filteredInventory.length === 0 && (
                    <div className="py-20 text-center text-gray-400">
                        <Database className="w-12 h-12 mx-auto mb-3 opacity-20" />
                        <p className="text-sm font-medium">暂无相关稻米数据</p>
                    </div>
                  )}
               </div>
            </div>
          )}

          {activeTab === 'users' && isAdmin && (
             <div className="space-y-6 animate-in fade-in duration-300">
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between">
                        <div>
                            <div className="text-xs text-gray-400 uppercase font-semibold mb-1">总注册量</div>
                            <div className="text-2xl font-bold text-gray-900">{users.length}</div>
                        </div>
                        <div className={`w-10 h-10 rounded-lg flex items-center justify-center bg-amber-50 text-amber-600`}>
                            <Users className="w-5 h-5" />
                        </div>
                    </div>
                    <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between">
                        <div>
                            <div className="text-xs text-gray-400 uppercase font-semibold mb-1">系统活跃</div>
                            <div className="text-2xl font-bold text-emerald-600">{users.filter(u => u.status === 'Active').length}</div>
                        </div>
                         <div className="w-10 h-10 bg-emerald-50 text-emerald-600 rounded-lg flex items-center justify-center">
                            <Activity className="w-5 h-5" />
                        </div>
                    </div>
                    <div className="bg-white p-5 rounded-xl border border-gray-100 shadow-sm flex items-center justify-between">
                        <div>
                            <div className="text-xs text-gray-400 uppercase font-semibold mb-1">被封禁账号</div>
                            <div className={`text-2xl font-bold text-red-600`}>{users.filter(u => u.status === 'Banned').length}</div>
                        </div>
                         <div className={`w-10 h-10 rounded-lg flex items-center justify-center bg-red-50 text-red-600`}>
                            <Ban className="w-5 h-5" />
                        </div>
                    </div>
                </div>

                <div className="flex justify-between items-center bg-white p-3 rounded-xl border border-gray-200">
                    <div className="relative w-full max-w-md">
                        <Search className="absolute left-3 top-2.5 w-4 h-4 text-gray-400" />
                        <input 
                            type="text" 
                            placeholder="通过用户名、UID 检索用户..." 
                            value={userSearch}
                            onChange={(e) => setUserSearch(e.target.value)}
                            className="w-full bg-gray-50 border-0 rounded-lg pl-10 pr-4 py-2 text-sm focus:ring-2 focus:ring-amber-500" 
                        />
                    </div>
                    <button 
                        onClick={openAddUserModal}
                        className="bg-amber-500 text-white px-4 py-2 rounded-lg text-sm font-medium hover:bg-amber-600 transition-colors flex items-center gap-2"
                    >
                        <UserPlus className="w-4 h-4" />
                        手动创建账户
                    </button>
                </div>

                <div className="bg-white rounded-xl border border-gray-200 overflow-hidden shadow-sm">
                    <table className="w-full text-sm text-left">
                        <thead className="bg-gray-50 text-gray-500 font-medium">
                            <tr>
                                <th className="px-6 py-4">UID</th>
                                <th className="px-6 py-4">账户</th>
                                <th className="px-6 py-4">来源 IP</th>
                                <th className="px-6 py-4">角色</th>
                                <th className="px-6 py-4">状态</th>
                                <th className="px-6 py-4">最近活动</th>
                                <th className="px-6 py-4 text-right">管控</th>
                            </tr>
                        </thead>
                        <tbody className="divide-y divide-gray-100">
                            {filteredUsers.map((user) => (
                                <tr key={user.id} className="hover:bg-gray-50 transition-colors">
                                    <td className="px-6 py-4 font-mono text-xs text-gray-400">{user.id}</td>
                                    <td className="px-6 py-4 font-medium text-gray-900 flex items-center gap-2">
                                        <div className="w-6 h-6 rounded-full bg-gray-100 flex items-center justify-center text-xs text-gray-500">
                                            {user.username.charAt(0).toUpperCase()}
                                        </div>
                                        {user.username}
                                    </td>
                                    <td className="px-6 py-4 text-gray-500 text-xs">{user.ip}</td>
                                    <td className={`px-6 py-4 text-xs font-bold ${user.role === 'Admin' ? 'text-amber-600' : user.role === 'Merchant' ? 'text-blue-600' : 'text-gray-600'}`}>
                                        {user.role === 'Admin' ? '系统管理员' : user.role === 'Merchant' ? '入驻商家' : '普通用户'}
                                    </td>
                                    <td className="px-6 py-4">
                                        <span className={`inline-flex items-center gap-1.5 px-2 py-1 rounded-full text-xs font-medium ${
                                            user.status === 'Active' ? 'bg-green-50 text-green-700' : 'bg-red-50 text-red-700'
                                        }`}>
                                            {user.status === 'Active' ? '活跃中' : '已冻结'}
                                        </span>
                                    </td>
                                    <td className="px-6 py-4 text-gray-500 text-xs">{user.lastActive}</td>
                                    <td className="px-6 py-4 text-right flex items-center justify-end gap-2">
                                        <button 
                                            onClick={() => openEditUserModal(user)}
                                            className="text-gray-400 hover:text-amber-600 transition-colors p-1.5"
                                        >
                                            <Pencil className="w-4 h-4" />
                                        </button>
                                        {user.id !== currentUser?.id && (
                                            <button 
                                                onClick={() => toggleUserStatus(user.id)}
                                                className={`transition-colors p-1.5 rounded ${
                                                    user.status === 'Active' ? 'text-gray-400 hover:text-red-600' : 'text-gray-400 hover:text-green-600'
                                                }`}
                                            >
                                                {user.status === 'Active' ? <Ban className="w-4 h-4" /> : <CheckCircle className="w-4 h-4" />}
                                            </button>
                                        )}
                                    </td>
                                </tr>
                            ))}
                        </tbody>
                    </table>
                </div>
             </div>
          )}
        </main>
      </div>

      {showAddModal && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4">
              <div className="bg-white rounded-2xl shadow-xl w-full max-w-2xl overflow-hidden animate-in fade-in zoom-in-95 duration-200 max-h-full overflow-y-auto">
                  <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50 sticky top-0 z-10">
                      <h3 className="font-bold text-gray-900">
                        {editingId ? '编辑商品信息' : '发布新稻米'}
                      </h3>
                      <button onClick={() => setShowAddModal(false)} className="text-gray-400 hover:text-gray-600">
                          <X className="w-5 h-5" />
                      </button>
                  </div>

                  <form onSubmit={handleSubmit} className="p-6 space-y-6">
                      <div className="grid grid-cols-2 gap-4">
                          <div className="col-span-2">
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">稻米名称</label>
                              <input required type="text" name="name" value={newProduct.name} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" placeholder="如：五常稻花香 1号" />
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">产地</label>
                              <input required type="text" name="origin" value={newProduct.origin} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" placeholder="如：黑龙江五常" />
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1 flex items-center gap-1">
                                <Link className="w-3 h-3 text-blue-500" /> 购买地址 (URL)
                              </label>
                              <input type="text" name="purchaseUrl" value={newProduct.purchaseUrl} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" placeholder="https://item.jd.com/..." />
                          </div>
                          <div className="col-span-2">
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-2">图片展示 (可上传多张)</label>
                              <div className="grid grid-cols-4 sm:grid-cols-5 gap-3">
                                  {newProduct.images?.map((img, idx) => (
                                      <div key={idx} className="aspect-square relative group rounded-lg overflow-hidden border border-gray-200 bg-white">
                                          <img src={img} alt="" className="w-full h-full object-cover" />
                                          <button 
                                            type="button"
                                            onClick={() => removeImage(idx)}
                                            className="absolute inset-0 bg-black/40 opacity-0 group-hover:opacity-100 flex items-center justify-center transition-opacity"
                                          >
                                              <Trash2 className="w-5 h-5 text-white" />
                                          </button>
                                          {idx === 0 && (
                                              <div className="absolute bottom-0 left-0 right-0 bg-emerald-500 text-white text-[8px] py-0.5 text-center font-bold">主图</div>
                                          )}
                                      </div>
                                  ))}
                                  <label className="aspect-square border-2 border-dashed border-gray-200 rounded-lg flex flex-col items-center justify-center cursor-pointer hover:border-blue-400 hover:bg-blue-50 transition-all text-gray-400 hover:text-blue-500">
                                      <Upload className="w-5 h-5 mb-1" />
                                      <span className="text-[10px] font-bold">上传图片</span>
                                      <input type="file" multiple accept="image/*" className="hidden" onChange={handleMultipleImageUpload} />
                                  </label>
                              </div>
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1 flex items-center gap-1">
                                <Droplets className="w-3 h-3 text-blue-500" /> 烹饪米水比
                              </label>
                              <input required type="text" name="cookingRatio" value={newProduct.cookingRatio} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm font-bold text-blue-600 focus:ring-2 focus:ring-blue-500" placeholder="1:1.2" />
                          </div>
                          <div>
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">零售价 (元/kg)</label>
                              <input required type="number" min="0" step="0.1" name="price" value={newProduct.price} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" />
                          </div>
                           <div>
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">当前库存</label>
                              <input type="number" min="0" name="stock" value={newProduct.stock} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" />
                          </div>
                           <div>
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">口感评分 (1-100)</label>
                              <input type="number" min="1" max="100" name="textureScore" value={newProduct.textureScore} onChange={handleInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500" />
                          </div>
                           <div className="col-span-2">
                              <label className="block text-xs font-bold text-gray-500 uppercase mb-1">产品描述</label>
                              <textarea name="description" value={newProduct.description} onChange={handleInputChange} rows={3} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-blue-500 resize-none" placeholder="详细介绍口感与特色..." />
                          </div>
                      </div>

                      <div className="pt-4 flex justify-end gap-3 border-t border-gray-100 mt-4">
                          <button type="button" onClick={() => setShowAddModal(false)} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg transition-colors">取消</button>
                          <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-blue-600 hover:bg-blue-700 rounded-lg flex items-center gap-2 transition-all shadow-md active:scale-95">
                              <Save className="w-4 h-4" />
                              {editingId ? '保存更改' : '确认上架'}
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}

      {showUserModal && isAdmin && (
          <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/20 backdrop-blur-sm p-4">
              <div className="bg-white rounded-2xl shadow-xl w-full max-w-sm overflow-hidden animate-in fade-in zoom-in-95 duration-200">
                  <div className="px-6 py-4 border-b border-gray-100 flex justify-between items-center bg-gray-50">
                      <h3 className="font-bold text-gray-900">
                        {editingUserId ? '修改用户信息' : '创建系统账户'}
                      </h3>
                      <button onClick={() => setShowUserModal(false)} className="text-gray-400 hover:text-gray-600">
                          <X className="w-5 h-5" />
                      </button>
                  </div>

                  <form onSubmit={handleUserSubmit} className="p-6 space-y-4">
                      <div>
                          <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">账户名称</label>
                          <input required type="text" name="username" value={userForm.username} onChange={handleUserInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-amber-500" />
                      </div>

                      <div>
                          <label className="block text-xs font-semibold text-gray-500 uppercase mb-1">赋予角色</label>
                          <select name="role" value={userForm.role} onChange={handleUserInputChange} className="w-full bg-gray-50 border-0 rounded-lg px-3 py-2 text-sm focus:ring-2 focus:ring-amber-500">
                              <option value="User">普通用户</option>
                              <option value="Merchant">入驻商家</option>
                              <option value="Admin">管理员</option>
                          </select>
                      </div>

                      <div className="pt-4 flex justify-end gap-3 pb-2">
                          <button type="button" onClick={() => setShowUserModal(false)} className="px-4 py-2 text-sm font-medium text-gray-600 hover:bg-gray-100 rounded-lg">放弃</button>
                          <button type="submit" className="px-6 py-2 text-sm font-medium text-white bg-amber-500 hover:bg-amber-600 rounded-lg flex items-center gap-2">
                              <Save className="w-4 h-4" />
                              确认提交
                          </button>
                      </div>
                  </form>
              </div>
          </div>
      )}
    </div>
  );
};

