               <div className="bg-blue-50/50 p-4 rounded-2xl border border-blue-100 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                     <div className="p-2 bg-blue-500 rounded-lg text-white">
                        <Droplets className="w-5 h-5" />
                     </div>
                     <div>
                        <h4 className="text-[10px] font-bold text-blue-600 uppercase tracking-widest">推荐烹饪米水比</h4>
                        <div className="text-lg font-bold text-blue-900">{product.cookingRatio}</div>
                     </div>
                  </div>
                  <div className="text-[10px] text-blue-400 font-medium text-right leading-tight max-w-[100px]">
                     即 100g 稻米约需 {(parseFloat(product.cookingRatio.split(':')[1]) * 100).toFixed(0)}ml 水
                  </div>
               </div>

               <div className="bg-emerald-50/80 p-5 rounded-2xl border border-emerald-100/50">
                  <h4 className="text-xs font-bold text-emerald-800 uppercase tracking-widest mb-2 flex items-center gap-2">
                    <Sparkles className="w-3.5 h-3.5" /> 推荐匹配理由
                  </h4>
                  <p className="text-sm text-emerald-900 leading-relaxed font-medium">
                    {product.matchReason || "深度契合您的偏好。"}
                  </p>
               </div>

               <div className="space-y-3">
                  <h4 className="text-xs font-bold text-gray-900 uppercase tracking-widest">产品特色详情</h4>
                  <p className="text-sm text-gray-600 leading-relaxed italic border-l-2 border-gray-100 pl-4">
                    {product.description}
                  </p>
               </div>

               <div className="flex-1 min-h-[20px]"></div>

               <div className="pt-6 border-t border-gray-100 flex flex-col gap-4">
                  {product.purchaseUrl && (
                      <a 
                        href={product.purchaseUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="w-full bg-blue-600 text-white py-4 rounded-2xl font-bold flex items-center justify-center gap-2 hover:bg-blue-700 transition-all shadow-lg shadow-blue-100 active:scale-95"
                      >
                        <ExternalLink className="w-5 h-5" />
                        前往商家购买
                      </a>
                  )}
                  <div className="text-[10px] text-gray-400 text-center font-medium">
                      商家确保库存充足，如有质量问题请联系平台管理员
                  </div>
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

