import React, { useState } from 'react';
import { X, UserPlus, LogIn, AlertCircle, Loader2 } from 'lucide-react';

interface UserAuthModalProps {
  initialMode?: 'login' | 'register';
  initialRole: 'User' | 'Merchant' | 'Admin';
  onClose: () => void;
  onLogin: (username: string, password?: string) => Promise<void>;
  onRegister: (username: string, password?: string, role?: 'User' | 'Merchant' | 'Admin') => Promise<void>;
}

const UserAuthModal: React.FC<UserAuthModalProps> = ({ initialMode = 'login', initialRole, onClose, onLogin, onRegister }) => {
  const [mode, setMode] = useState<'login' | 'register'>(initialMode);
  const [username, setUsername] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const [isSubmitting, setIsSubmitting] = useState(false);

  const validatePassword = (pwd: string): boolean => {
    let typesCount = 0;
    if (/[a-zA-Z]/.test(pwd)) typesCount++;
    if (/[0-9]/.test(pwd)) typesCount++;
    if (/[^a-zA-Z0-9]/.test(pwd)) typesCount++;
    return typesCount >= 2;
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!username || !password) {
      setError("请输入完整的账号和密码");
      return;
    }

    if (mode === 'register') {
      if (password.length < 6) {
        setError("密码长度不能少于6位");
        return;
      }
      if (!validatePassword(password)) {
        setError("密码要求：必须包含数字、字母或符号中的至少两种");
        return;
      }
    }

    setError('');
    setIsSubmitting(true);
    try {
      if (mode === 'login') {
        await onLogin(username, password);
      } else {
        await onRegister(username, password, initialRole);
      }
      onClose();
    } catch (err: any) {
      console.error("Auth Error:", err);
      setError(err.message || "过程中发生未知错误，请检查账号密码");
    } finally {
      setIsSubmitting(false);
    }
  };

  const getRoleTheme = () => {
    switch(initialRole) {
      case 'Admin': return { color: 'amber', label: '系统管理总台' };
      case 'Merchant': return { color: 'blue', label: '商家管理中心' };
      default: return { color: 'emerald', label: '普通用户门户' };
    }
  };

  const theme = getRoleTheme();

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center bg-black/60 backdrop-blur-md p-4 animate-in fade-in duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-sm overflow-hidden animate-in zoom-in-95 duration-300">
        <div className={`px-6 py-5 border-b border-gray-100 flex justify-between items-center bg-${theme.color}-50/30`}>
          <div className="flex flex-col">
            <h3 className="font-bold text-gray-900 leading-tight">
              {mode === 'login' ? '账户登录' : '新账户注册'}
            </h3>
            <span className={`text-[10px] font-bold uppercase tracking-widest mt-0.5 text-${theme.color}-600`}>
                {theme.label}
            </span>
          </div>
          <button onClick={onClose} className="p-1 text-gray-400 hover:text-gray-600 transition-colors bg-white/50 rounded-full">
            <X className="w-5 h-5" />
          </button>
        </div>

        <form onSubmit={handleSubmit} className="p-8 space-y-5">
          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">用户名</label>
            <input
              type="text"
              disabled={isSubmitting}
              value={username}
              onChange={(e) => { setUsername(e.target.value); setError(''); }}
              className={`w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm transition-all placeholder-gray-300 disabled:opacity-50 focus:ring-2 focus:ring-${theme.color}-500`}
              placeholder="请输入您的账号"
            />
          </div>

          <div>
            <label className="block text-[10px] font-bold text-gray-400 uppercase tracking-widest mb-2">账户密码</label>
            <input
              type="password"
              disabled={isSubmitting}
              value={password}
              onChange={(e) => { setPassword(e.target.value); setError(''); }}
              className={`w-full bg-gray-50 border-0 rounded-xl px-4 py-3.5 text-sm transition-all placeholder-gray-300 disabled:opacity-50 focus:ring-2 focus:ring-${theme.color}-500`}
              placeholder="请输入您的密码"
            />
            {mode === 'register' && (
              <p className="mt-2 text-[10px] text-gray-400">
                提示：密码需包含数字、字母或符号中的至少两种。
              </p>
            )}
          </div>

          {error && (
            <div className="flex items-center gap-2 text-xs text-red-600 bg-red-50 p-3.5 rounded-xl border border-red-100 animate-in shake duration-300">
              <AlertCircle className="w-4 h-4 flex-shrink-0" />
              {error}
            </div>
          )}

          <button
            type="submit"
            disabled={isSubmitting}
            className={`w-full text-white py-4 rounded-2xl font-bold transition-all flex justify-center items-center gap-2 shadow-xl active:scale-95 disabled:opacity-70 bg-${theme.color}-500 hover:bg-${theme.color}-600 shadow-${theme.color}-200`}
          >
            {isSubmitting ? (
              <Loader2 className="w-5 h-5 animate-spin" />
            ) : mode === 'login' ? (
              <>
                <LogIn className="w-4 h-4" /> 确认登录
              </>
            ) : (
              <>
                <UserPlus className="w-4 h-4" /> 立即注册
              </>
            )}
          </button>

          {initialRole !== 'Admin' && (
              <div className="text-center pt-2">
                <button
                  type="button"
                  disabled={isSubmitting}
                  onClick={() => {
                    setMode(mode === 'login' ? 'register' : 'login');
                    setError('');
                  }}
                  className={`text-xs font-bold transition-colors disabled:opacity-50 text-${theme.color}-600 hover:text-${theme.color}-700`}
                >
                  {mode === 'login' ? '还没有账号？前往注册' : '已有账号？前往登录'}
                </button>
              </div>
          )}
        </form>
      </div>
    </div>
  );
};

export default UserAuthModal;

