const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>(null);
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [inventory, setInventory] = useState<RiceProduct[]>([]);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isDataFetching, setIsDataFetching] = useState(true);
  const [results, setResults] = useState<RecommendationResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authConfig, setAuthConfig] = useState<{mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin'}>({mode: 'login', role: 'User'});
  const [viewMode, setViewMode] = useState<'search' | 'favorites'>('search');
  const [selectedProductForModal, setSelectedProductForModal] = useState<RiceProduct | null>(null);

  useEffect(() => {
    const initApp = async () => {
      try {
        const [products, allUsers] = await Promise.all([
          RiceApi.fetchProducts(),
          RiceApi.fetchUsers()
        ]);
        setInventory(products);
        setUsers(allUsers);
      } catch (err) {
        setError("无法连接到系统服务，请稍后重试。");
      } finally {
        setIsDataFetching(false);
      }
    };
    initApp();
  }, []);

  const handleLoginPortal = (role: UserRole) => {
    setUserRole(role);
    setResults(null); 
    setViewMode('search');
    if (role === 'merchant' || role === 'admin') setCurrentUser(null);
  };

  const handleOpenAuth = (mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin') => {
      setAuthConfig({ mode, role });
      setShowAuthModal(true);
  };

  const handleLogout = () => {
    setUserRole(null);
    setResults(null);
    setCurrentUser(null);
    setViewMode('search');
  };

  const handleAddProduct = async (newProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(newProduct);
    setInventory(prev => [...prev.filter(p => p.id !== saved.id), saved]);
  };

  const handleUpdateProduct = async (updatedProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(updatedProduct);
    setInventory(prev => prev.map(p => p.id === saved.id ? saved : p));
  };

  const handleUpdateUsers = (updatedUsers: UserProfile[]) => {
      setUsers(updatedUsers);
  };

  const handleClientRegister = async (username: string, password?: string, role: 'User' | 'Merchant' | 'Admin' = 'User') => {
    const newUser: UserProfile = {
      id: `${role === 'Merchant' ? 'M' : role === 'Admin' ? 'A' : 'U'}${Date.now()}`,
      username,
      password, 
      role,
      status: 'Active',
      ip: '127.0.0.1', 
      lastActive: '刚刚',
      requestCount: 0,
      favorites: []
    };
    const registered = await RiceApi.register(newUser);
    setUsers(prev => [registered, ...prev]);
    setCurrentUser(registered);
    setUserRole(role === 'Merchant' ? 'merchant' : role === 'Admin' ? 'admin' : 'user');
    setShowAuthModal(false);
  };

  const handleClientLogin = async (username: string, password?: string) => {
    const user = users.find(u => u.username === username && u.password === password);

    if (!user) {
      throw new Error("账号或密码错误");
    }

    if (user.status !== 'Active') {
      throw new Error("您的账号已被锁定，请联系系统总管理员。");
    }

    const updatedUser = { ...user, lastActive: '刚刚' };
    setCurrentUser(updatedUser);
    setUserRole(user.role === 'Merchant' ? 'merchant' : user.role === 'Admin' ? 'admin' : 'user');

    setUsers(prev => prev.map(u => u.id === user.id ? updatedUser : u));
    await RiceApi.syncUser(updatedUser);
    setShowAuthModal(false);
  };

  const toggleFavorite = async (productId: string) => {
    if (!currentUser) {
      handleOpenAuth('login', 'User');
      return;
    }

    const isFav = currentUser.favorites.includes(productId);
    const updatedUser = {
        ...currentUser,
        favorites: isFav ? currentUser.favorites.filter(id => id !== productId) : [...currentUser.favorites, productId]
    };

    setCurrentUser(updatedUser);
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    await RiceApi.syncUser(updatedUser);
  };

  const handlePreferenceSubmit = async (prefs: UserPreferences) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.getRecommendations(prefs);
      setResults(data);
    } catch (err) {
      setError("服务请求超时，请重新提交匹配。");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSubmit = async (base64: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.analyzeImage(base64);
      setResults(data);
    } catch (err) {
      setError("识别服务暂时不可用。");
    } finally {
      setIsLoading(false);
    }
  }

  const reset = () => {
    setResults(null);
    setViewMode('search');
    window.scrollTo({ top: 0, behavior: 'smooth' });
  };

  // 侧边栏逻辑
  const favoritesInSidebar = useMemo(() => {
    if (!currentUser) return [];
    return inventory.filter(p => currentUser.favorites.includes(p.id)).slice(0, 10);
  }, [currentUser, inventory]);

  const hotProducts = useMemo(() => {
    return [...inventory].sort((a, b) => (b.stock || 0) - (a.stock || 0)).slice(0, 6);
  }, [inventory]);

  const personalizedRecs = useMemo(() => {
    if (!currentUser || currentUser.favorites.length === 0) return [];
    const favOrigins = inventory.filter(p => currentUser.favorites.includes(p.id)).map(p => p.origin);
    return inventory
      .filter(p => !currentUser.favorites.includes(p.id) && favOrigins.includes(p.origin))
      .slice(0, 6);
  }, [currentUser, inventory]);

  const isOldUser = currentUser && currentUser.favorites.length > 0;

  if (isDataFetching) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-gray-50 text-gray-400">
        <Loader2 className="w-10 h-10 animate-spin text-emerald-500 mb-4" />
        <p className="text-sm font-medium animate-pulse">正在加载系统数据...</p>
      </div>
    );
  }

  let mainContent;
  if (!userRole) {
    mainContent = <Login onLogin={handleLoginPortal} onOpenAuth={handleOpenAuth} />;
  } else if (userRole === 'merchant' || userRole === 'admin') {
    mainContent = (
      <AdminDashboard 
        onLogout={handleLogout} 
        inventory={inventory}
        onAddProduct={handleAddProduct}
        onUpdateProduct={handleUpdateProduct}
        users={users}
        onUpdateUsers={handleUpdateUsers}
        currentUser={currentUser}
      />
    );
  } else {
    // 普通用户界面
    const favoriteProducts = currentUser 
      ? inventory.filter(p => currentUser.favorites.includes(p.id))
      : [];

    mainContent = (
      <div className="min-h-screen bg-[#fafafa] text-gray-900 font-sans selection:bg-emerald-100 relative">
        <nav className="fixed top-0 left-0 w-full p-4 flex justify-between items-center z-[80] bg-white/60 backdrop-blur-md border-b border-gray-100 shadow-sm">
            <div className="flex items-center gap-3">
               {!currentUser ? (
                 <button onClick={() => handleOpenAuth('login', 'User')} className="flex items-center gap-2 bg-emerald-600 shadow-md shadow-emerald-200 px-5 py-2 rounded-full text-sm font-bold text-white hover:bg-emerald-700 transition-all active:scale-95">
                   <LogIn className="w-4 h-4" /> 登录 / 注册
                 </button>
               ) : (
                  <div className="flex items-center gap-2">
                     <div className="flex items-center gap-2 bg-gray-100 px-4 py-2 rounded-full text-xs font-bold text-gray-700">
                        <div className="w-5 h-5 bg-emerald-500 text-white rounded-full flex items-center justify-center text-[10px]">
                          {currentUser.username.charAt(0).toUpperCase()}
                        </div>
                        你好，{currentUser.username}
                     </div>
                     <button 
                        onClick={() => setViewMode(viewMode === 'search' ? 'favorites' : 'search')}
                        className={`flex items-center gap-2 px-4 py-2 rounded-full text-xs font-bold transition-all shadow-sm border ${viewMode === 'favorites' ? 'bg-red-500 text-white border-red-500 shadow-red-200' : 'bg-white text-gray-600 border-gray-200 hover:text-red-500'}`}
                     >
                        <Heart className={`w-3.5 h-3.5 ${viewMode === 'favorites' ? 'fill-current' : ''}`} />
                        收藏夹 ({currentUser.favorites.length})
                     </button>
                  </div>
               )}
            </div>
            <button onClick={handleLogout} className="text-[10px] text-gray-400 hover:text-red-500 flex items-center gap-1 transition-colors px-3 py-2 rounded-lg hover:bg-red-50 font-bold">
                <LogOut className="w-3 h-3" /> 退出系统
            </button>
        </nav>

        <div className="w-full max-w-[1600px] mx-auto px-4 md:px-8 pt-24 pb-12">
          {viewMode === 'favorites' && currentUser ? (
             <div className="animate-in fade-in slide-in-from-bottom-4 duration-500">
                <div className="flex items-center justify-between mb-8">
                   <h2 className="text-3xl font-bold text-gray-900 flex items-center gap-3">
                      <Heart className="w-8 h-8 text-red-500 fill-red-500" /> 我的收藏夹
                   </h2>
                   <button onClick={() => setViewMode('search')} className="text-sm font-bold text-emerald-600 hover:text-emerald-700 underline underline-offset-4">
                      返回搜索推荐
                   </button>
                </div>
                <ResultsGrid products={favoriteProducts} analysisText="" favorites={currentUser.favorites} onToggleFavorite={toggleFavorite} showAnalysis={false} />
             </div>
          ) : (
            <div className="flex flex-col lg:flex-row gap-8">
              {/* Left Sidebar: Favorites (Only if logged in) */}
              {currentUser && (
                <aside className="lg:w-64 flex-shrink-0 space-y-6">
                  <div className="bg-white/60 backdrop-blur rounded-2xl p-4 border border-gray-100 shadow-sm sticky top-24">
                    <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.15em] mb-4 flex items-center gap-2">
                      <Heart className="w-3 h-3 text-red-500 fill-red-500" /> 我的快速收藏
                    </h3>
                    <div className="space-y-1">
                      {favoritesInSidebar.length > 0 ? (
                        favoritesInSidebar.map(p => (
                          <SidebarItem key={p.id} product={p} onClick={() => setSelectedProductForModal(p)} />
                        ))
                      ) : (
                        <div className="py-8 text-center px-2">
                          <p className="text-[10px] text-gray-400 font-medium">暂无收藏商品，快去探索吧！</p>
                        </div>
                      )}
                    </div>
                  </div>
                </aside>
              )}

              {/* Center Content */}
              <div className="flex-1 min-w-0">
                <div className={`transition-all duration-700 ${results ? 'mb-12' : 'flex flex-col items-center justify-center min-h-[70vh]'}`}>
                    <div className="w-full max-w-3xl mx-auto">
                        <Hero />
                        {!results && (
                            <div className="animate-in fade-in slide-in-from-bottom-4 duration-700 w-full">
                                <PreferenceForm onSubmitPreferences={handlePreferenceSubmit} onSubmitImage={handleImageSubmit} isLoading={isLoading} />
                            </div>
                        )}
                    </div>
                </div>

                {results && (
                    <div className="w-full animate-in fade-in slide-in-from-bottom-12 duration-1000 space-y-8">
                        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white/40 backdrop-blur p-4 rounded-3xl border border-white/50 shadow-sm">
                            <div className="flex flex-col">
                               <h2 className="text-2xl font-black text-gray-900 flex items-center gap-3">
                                  <Search className="w-7 h-7 text-emerald-600" /> 推荐结果
                               </h2>
                            </div>
                            <button onClick={reset} className="flex items-center justify-center gap-2 text-sm font-bold text-gray-500 hover:text-emerald-600 transition-all px-6 py-2.5 rounded-full hover:bg-white bg-gray-50/50 shadow-sm border border-transparent hover:border-emerald-100">
                                <RotateCcw className="w-4 h-4" /> 重新匹配
                            </button>
                        </div>

                        <div className="grid grid-cols-1 gap-8">
                           <AnalysisChart products={results.recommendations} />
                           <ResultsGrid products={results.recommendations} analysisText={results.analysis} favorites={currentUser?.favorites || []} onToggleFavorite={toggleFavorite} />
                        </div>
                    </div>
                )}

                {error && (
                  <div className="max-w-md mx-auto mt-8 p-4 bg-red-50 border border-red-100 rounded-2xl text-red-600 text-sm font-medium flex items-center gap-3">
                     <div className="w-2 h-2 bg-red-500 rounded-full animate-ping"></div>
                     {error}
                  </div>
                )}
              </div>

              {/* Right Sidebar: Hot or Personalized */}
              {currentUser && (
                <aside className="lg:w-64 flex-shrink-0 space-y-6">
                  <div className="bg-white/60 backdrop-blur rounded-2xl p-4 border border-gray-100 shadow-sm sticky top-24">
                    {isOldUser ? (
                      <>
                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.15em] mb-4 flex items-center gap-2">
                          <Sparkles className="w-3 h-3 text-amber-500" /> 为您精选推荐
                        </h3>
                        <div className="space-y-1">
                          {personalizedRecs.map(p => (
                            <SidebarItem key={p.id} product={p} onClick={() => setSelectedProductForModal(p)} />
                          ))}
                        </div>
                      </>
                    ) : (
                      <>
                        <h3 className="text-xs font-black text-gray-400 uppercase tracking-[0.15em] mb-4 flex items-center gap-2">
                          <Flame className="w-3 h-3 text-orange-500" /> 全网人气稻米
                        </h3>
                        <div className="space-y-1">
                          {hotProducts.map(p => (
                            <SidebarItem key={p.id} product={p} onClick={() => setSelectedProductForModal(p)} />
                          ))}
                        </div>
                      </>
                    )}
                    <div className="mt-4 pt-4 border-t border-gray-100">
                        <div className="flex items-center gap-2 bg-emerald-50 p-3 rounded-xl">
                            <ShoppingBag className="w-4 h-4 text-emerald-600" />
                            <div className="flex flex-col">
                                <span className="text-[10px] font-bold text-emerald-700">新米专场</span>
                                <span className="text-[8px] text-emerald-600 opacity-70">限时折扣中</span>
                            </div>
                        </div>
                    </div>
                  </div>
                </aside>
              )}
            </div>
          )}
        </div>
      </div>
    );
  }

  return (
    <>
      {mainContent}

      {showAuthModal && (
        <UserAuthModal 
            initialMode={authConfig.mode}
            initialRole={authConfig.role}
            onClose={() => setShowAuthModal(false)} 
            onLogin={handleClientLogin} 
            onRegister={handleClientRegister} 
        />
      )}
    </>
  );
};

export default App;

import React, { useState, useEffect, useMemo } from 'react';
import { UserPreferences, RecommendationResponse, UserRole, RiceProduct, UserProfile } from './types.ts';
import { RiceApi } from './services/apiService.ts';
import Hero from './components/Hero.tsx';
import PreferenceForm from './components/PreferenceForm.tsx';
import ResultsGrid from './components/ResultsGrid.tsx';
import AnalysisChart from './components/AnalysisChart.tsx';
import Login from './components/Login.tsx';
import AdminDashboard from './components/AdminDashboard.tsx';
import UserAuthModal from './components/UserAuthModal.tsx';
import { RotateCcw, LogOut, Heart, Search, LogIn, Loader2, Flame, Sparkles, ShoppingBag, ChevronRight, Bookmark } from 'lucide-react';
import { ProductDetailModal } from './components/ResultsGrid.tsx';

const SidebarItem: React.FC<{ product: RiceProduct; onClick: () => void }> = ({ product, onClick }) => (
  <div 
    onClick={onClick}
    className="group flex items-center gap-3 p-2.5 rounded-xl hover:bg-white hover:shadow-md border border-transparent hover:border-gray-100 transition-all cursor-pointer animate-in fade-in duration-300"
  >
    <div className="w-11 h-11 rounded-lg bg-gray-50 overflow-hidden flex-shrink-0 border border-gray-100">
      <img src={product.images?.[0] || product.packagingImage} alt="" className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-500" />
    </div>
    <div className="flex-1 min-w-0">
      <h4 className="text-[11px] font-bold text-gray-800 truncate">{product.name}</h4>
      <div className="flex items-center justify-between mt-1">
        <span className="text-[10px] text-emerald-600 font-bold font-mono">¥{product.price}</span>
        <span className="text-[9px] text-gray-400">{product.origin.slice(0, 3)}</span>
      </div>
    </div>
    <ChevronRight className="w-3 h-3 text-gray-300 group-hover:text-emerald-500 transition-colors" />
  </div>
);

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>(null);
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [inventory, setInventory] = useState<RiceProduct[]>([]);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isDataFetching, setIsDataFetching] = useState(true);
  const [results, setResults] = useState<RecommendationResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authConfig, setAuthConfig] = useState<{mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin'}>({mode: 'login', role: 'User'});
  const [viewMode, setViewMode] = useState<'search' | 'favorites'>('search');
  const [selectedProduct, setSelectedProduct] = useState<RiceProduct | null>(null);

  useEffect(() => {
    const initApp = async () => {
      try {
        const [products, allUsers] = await Promise.all([
          RiceApi.fetchProducts(),
          RiceApi.fetchUsers()
        ]);
        setInventory(products);
        setUsers(allUsers);
      } catch (err) {
        setError("系统服务连接异常");
      } finally {
        setIsDataFetching(false);
      }
    };
    initApp();
  }, []);

  const handleLoginPortal = (role: UserRole) => {
    setUserRole(role);
    setResults(null); 
    setViewMode('search');
    if (role === 'merchant' || role === 'admin') setCurrentUser(null);
  };

  const handleOpenAuth = (mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin') => {
      setAuthConfig({ mode, role });
      setShowAuthModal(true);
  };

  const handleLogout = () => {
    setUserRole(null);
    setResults(null);
    setCurrentUser(null);
    setViewMode('search');
  };

  const handleAddProduct = async (newProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(newProduct);
    setInventory(prev => [saved, ...prev.filter(p => p.id !== saved.id)]);
  };

  const handleUpdateProduct = async (updatedProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(updatedProduct);
    setInventory(prev => prev.map(p => p.id === saved.id ? saved : p));
  };

  const handleUpdateUsers = (updatedUsers: UserProfile[]) => setUsers(updatedUsers);

  const handleClientRegister = async (username: string, password?: string, role: 'User' | 'Merchant' | 'Admin' = 'User') => {
    const newUser: UserProfile = {
      id: `${role === 'Merchant' ? 'M' : role === 'Admin' ? 'A' : 'U'}${Date.now()}`,
      username, password, role, status: 'Active',
      ip: '127.0.0.1', lastActive: '刚刚', requestCount: 0, favorites: []
    };
    const registered = await RiceApi.register(newUser);
    setUsers(prev => [registered, ...prev]);
    setCurrentUser(registered);
    setUserRole(role === 'Merchant' ? 'merchant' : role === 'Admin' ? 'admin' : 'user');
    setShowAuthModal(false);
  };

  const handleClientLogin = async (username: string, password?: string) => {
    const user = users.find(u => u.username === username && u.password === password);
    if (!user) throw new Error("账号或密码错误");
    if (user.status !== 'Active') throw new Error("账号被封禁");

    const updatedUser = { ...user, lastActive: '刚刚' };
    setCurrentUser(updatedUser);
    setUserRole(user.role === 'Merchant' ? 'merchant' : user.role === 'Admin' ? 'admin' : 'user');
    setUsers(prev => prev.map(u => u.id === user.id ? updatedUser : u));
    await RiceApi.syncUser(updatedUser);
    setShowAuthModal(false);
  };

  const toggleFavorite = async (productId: string) => {
    if (!currentUser) return handleOpenAuth('login', 'User');
    const isFav = currentUser.favorites.includes(productId);
    const updatedUser = {
        ...currentUser,
        favorites: isFav ? currentUser.favorites.filter(id => id !== productId) : [...currentUser.favorites, productId]
    };
    setCurrentUser(updatedUser);
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    await RiceApi.syncUser(updatedUser);
  };

  const handlePreferenceSubmit = async (prefs: UserPreferences) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.getRecommendations(prefs);
      setResults(data);
    } catch (err) {
      setError("匹配服务超时");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSubmit = async (base64: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.analyzeImage(base64);
      setResults(data);
    } catch (err) {
      setError("AI分析暂时不可用");
    } finally {
      setIsLoading(false);
    }
  }

  // 特征融合推荐逻辑
  const favoritesInSidebar = useMemo(() => {
    if (!currentUser) return [];
    return inventory.filter(p => currentUser.favorites.includes(p.id)).slice(0, 10);
  }, [currentUser, inventory]);

  const hotProducts = useMemo(() => {
    return [...inventory].sort((a, b) => (b.stock || 0) - (a.stock || 0)).slice(0, 6);
  }, [inventory]);

  const personalizedRecs = useMemo(() => {
    if (!currentUser || currentUser.favorites.length === 0) return [];
    const favs = inventory.filter(p => currentUser.favorites.includes(p.id));
    const avgTexture = favs.reduce((acc, p) => acc + p.textureScore, 0) / favs.length;
    const avgAroma = favs.reduce((acc, p) => acc + p.aromaScore, 0) / favs.length;
    const origins = new Set(favs.map(p => p.origin));

    return inventory
      .filter(p => !currentUser.favorites.includes(p.id))
      .map(p => {
        let score = 0;
        if (origins.has(p.origin)) score += 50;
        score += (100 - Math.abs(p.textureScore - avgTexture));
        score += (100 - Math.abs(p.aromaScore - avgAroma));
        return { product: p, score };
      })
      .sort((a, b) => b.score - a.score)
      .slice(0, 6)
      .map(item => item.product);
  }, [currentUser, inventory]);

  const isOldUser = currentUser && currentUser.favorites.length > 0;

  if (isDataFetching) {
    return (
      <div className="min-h-screen flex flex-col items-center justify-center bg-white text-gray-400">
        <Loader2 className="w-8 h-8 animate-spin text-emerald-500 mb-2" />
        <span className="text-xs font-bold uppercase tracking-widest opacity-50">System Initializing</span>
      </div>
    );
  }

  if (!userRole) return <Login onLogin={handleLoginPortal} onOpenAuth={handleOpenAuth} />;

  if (userRole === 'merchant' || userRole === 'admin') {
    return <AdminDashboard onLogout={handleLogout} inventory={inventory} onAddProduct={handleAddProduct} onUpdateProduct={handleUpdateProduct} users={users} onUpdateUsers={handleUpdateUsers} currentUser={currentUser} />;
  }

  return (
    <div className="min-h-screen bg-[#F6F8FA] text-gray-900 font-sans relative overflow-x-hidden">
      {/* 顶部导航 */}
      <nav className="fixed top-0 left-0 w-full px-8 py-3.5 flex justify-between items-center z-[100] bg-white/80 backdrop-blur-xl border-b border-gray-100 shadow-sm">
        <div className="flex items-center gap-6">
          <div className="flex items-center gap-2.5">
            <div className="w-8 h-8 bg-emerald-600 rounded-lg flex items-center justify-center shadow-lg shadow-emerald-200">
               <Bookmark className="w-4 h-4 text-white" />
            </div>
            <h1 className="font-black text-lg tracking-tight">RICE<span className="text-emerald-600">HUB</span></h1>
          </div>
          <div className="hidden md:flex items-center gap-1 bg-gray-100 p-1 rounded-xl">
             <button onClick={() => setViewMode('search')} className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${viewMode === 'search' ? 'bg-white shadow-sm text-gray-900' : 'text-gray-500 hover:text-gray-700'}`}>智能探索</button>
             <button onClick={() => setViewMode('favorites')} className={`px-4 py-1.5 text-xs font-bold rounded-lg transition-all ${viewMode === 'favorites' ? 'bg-white shadow-sm text-red-600' : 'text-gray-500 hover:text-red-500'}`}>收藏库</button>
          </div>
        </div>

        <div className="flex items-center gap-4">
           {currentUser ? (
             <div className="flex items-center gap-3 pr-2 border-r border-gray-200">
                <div className="text-right">
                   <div className="text-[10px] font-black text-gray-400 uppercase leading-none mb-0.5">Welcome Back</div>
                   <div className="text-xs font-bold text-gray-800">{currentUser.username}</div>
                </div>
                <div className="w-8 h-8 rounded-full bg-emerald-50 text-emerald-600 font-bold flex items-center justify-center text-xs border border-emerald-100">
                  {currentUser.username.charAt(0).toUpperCase()}
                </div>
             </div>
           ) : (
             <button onClick={() => handleOpenAuth('login', 'User')} className="bg-emerald-600 text-white px-5 py-2 rounded-full text-xs font-bold hover:bg-emerald-700 transition-all shadow-lg shadow-emerald-100">立即登录</button>
           )}
           <button onClick={handleLogout} className="p-2 text-gray-400 hover:text-red-500 transition-colors">
              <LogOut className="w-4 h-4" />
           </button>
        </div>
      </nav>

      <div className="w-full max-w-[1680px] mx-auto px-6 pt-24 pb-12 flex flex-col lg:flex-row gap-6 h-[calc(100vh-80px)]">
        {/* 左侧收藏夹 - 桌面端固定 */}
        <aside className="lg:w-[280px] flex-shrink-0 flex flex-col gap-4 overflow-hidden h-full">
           <div className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm flex flex-col h-full">
              <div className="flex items-center justify-between mb-5">
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                  <Heart className="w-3.5 h-3.5 text-red-500 fill-red-500" /> 我的收藏
                </h3>
                <span className="text-[10px] font-bold text-gray-400 bg-gray-50 px-2 py-0.5 rounded-full">{currentUser?.favorites.length || 0}</span>
              </div>
              <div className="flex-1 overflow-y-auto custom-scrollbar pr-1 space-y-1">
                {favoritesInSidebar.length > 0 ? (
                  favoritesInSidebar.map(p => (
                    <SidebarItem key={p.id} product={p} onClick={() => setSelectedProduct(p)} />
                  ))
                ) : (
                  <div className="h-full flex flex-col items-center justify-center opacity-30 px-4 text-center">
                    <Bookmark className="w-8 h-8 mb-2" />
                    <p className="text-[10px] font-bold">暂无收藏商品</p>
                  </div>
                )}
              </div>
           </div>
        </aside>

        {/* 中间核心交互区 */}
        <main className="flex-1 min-w-0 flex flex-col gap-6 overflow-y-auto custom-scrollbar px-1">
           {viewMode === 'favorites' ? (
              <div className="animate-in fade-in duration-500">
                 <div className="bg-white p-6 rounded-2xl border border-gray-100 shadow-sm mb-6">
                    <h2 className="text-2xl font-black text-gray-900">我的稻米收藏库</h2>
                    <p className="text-sm text-gray-500 mt-1">您在此可以查看所有感兴趣的大米品种</p>
                 </div>
                 <ResultsGrid 
                    products={inventory.filter(p => currentUser?.favorites.includes(p.id))} 
                    analysisText="" 
                    favorites={currentUser?.favorites || []} 
                    onToggleFavorite={toggleFavorite} 
                    showAnalysis={false} 
                 />
              </div>
           ) : (
              <>
                 <div className={`transition-all duration-700 ${results ? 'mb-0' : 'flex flex-col items-center justify-center min-h-[40vh] mt-10'}`}>
                    <div className="w-full max-w-2xl mx-auto">
                        <Hero />
                        <PreferenceForm onSubmitPreferences={handlePreferenceSubmit} onSubmitImage={handleImageSubmit} isLoading={isLoading} />
                    </div>
                 </div>

                 {results && (
                    <div className="animate-in fade-in slide-in-from-bottom-8 duration-700 space-y-6 pb-10">
                        <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-5 rounded-2xl border border-gray-100 shadow-sm">
                            <div>
                               <h2 className="text-xl font-black text-gray-900 flex items-center gap-2">
                                  <Search className="w-5 h-5 text-emerald-600" /> 智能匹配分析
                               </h2>
                               <p className="text-xs text-gray-400 font-bold uppercase mt-0.5">Recommended Selection</p>
                            </div>
                            <button onClick={() => { setResults(null); window.scrollTo({top:0, behavior:'smooth'}); }} className="flex items-center gap-2 text-xs font-bold text-gray-500 hover:text-emerald-600 transition-all px-6 py-2.5 rounded-xl bg-gray-50 border border-transparent hover:border-emerald-100">
                                <RotateCcw className="w-3.5 h-3.5" /> 重新开始搜索
                            </button>
                        </div>
                        <AnalysisChart products={results.recommendations} />
                        <ResultsGrid 
                           products={results.recommendations} 
                           analysisText={results.analysis} 
                           favorites={currentUser?.favorites || []} 
                           onToggleFavorite={toggleFavorite} 
                        />
                    </div>
                 )}
              </>
           )}
        </main>

        {/* 右侧智能推荐栏 - 桌面端固定 */}
        <aside className="lg:w-[280px] flex-shrink-0 flex flex-col gap-4 overflow-hidden h-full">
           <div className="bg-white rounded-2xl p-5 border border-gray-100 shadow-sm flex flex-col h-full">
              <div className="flex items-center justify-between mb-5">
                <h3 className="text-xs font-black text-gray-400 uppercase tracking-widest flex items-center gap-2">
                  {isOldUser ? <Sparkles className="w-3.5 h-3.5 text-amber-500" /> : <Flame className="w-3.5 h-3.5 text-orange-500" />}
                  {isOldUser ? '猜你喜欢' : '人气推荐'}
                </h3>
                <div className="w-2 h-2 rounded-full bg-emerald-500 animate-pulse"></div>
              </div>

              <div className="flex-1 overflow-y-auto custom-scrollbar pr-1 space-y-1">
                {(isOldUser ? personalizedRecs : hotProducts).map(p => (
                  <SidebarItem key={p.id} product={p} onClick={() => setSelectedProduct(p)} />
                ))}
              </div>

              <div className="mt-4 pt-4 border-t border-gray-50">
                 <div className="bg-emerald-50/50 p-4 rounded-xl border border-emerald-100/50">
                    <div className="flex items-center gap-3 mb-2">
                       <ShoppingBag className="w-4 h-4 text-emerald-600" />
                       <span className="text-[10px] font-black text-emerald-700 uppercase tracking-tighter">New Arrivals</span>
                    </div>
                    <p className="text-[10px] text-emerald-800/70 font-medium leading-relaxed">
                       五常核心区新米已全面上市，全站订单限时 8.8 折起。
                    </p>
                 </div>
              </div>
           </div>
        </aside>
      </div>

      {/* 公用详情弹窗 */}
      {selectedProduct && (
          <ProductDetailModal 
            product={selectedProduct} 
            onClose={() => setSelectedProduct(null)} 
            isFavorite={currentUser?.favorites.includes(selectedProduct.id)}
            onToggleFavorite={toggleFavorite}
            accentColor="bg-emerald-500"
          />
      )}

      {showAuthModal && (
        <UserAuthModal 
            initialMode={authConfig.mode}
            initialRole={authConfig.role}
            onClose={() => setShowAuthModal(false)} 
            onLogin={handleClientLogin} 
            onRegister={handleClientRegister} 
        />
      )}
    </div>
  );
};

export default App;

