                     >
                         <span className="flex items-center gap-2">
                           {formData.aroma ? <Sparkles className="w-3.5 h-3.5" /> : null}
                           浓郁米香味
                         </span>
                         {formData.aroma && <Check className="w-4 h-4" />}
                     </button>
                </div>
            </div>

            {/* Requirements Text Area */}
