            {isLoading ? '特征融合模型计算中...' : '启动智能特征分析'}
          </button>
        </form>
      ) : (
        <div className="space-y-8 animate-in fade-in duration-500">
          <div className="text-center mb-6">
            <h3 className="text-xl font-black text-gray-900">视觉口味分析引擎</h3>
