        <p className="text-xs text-gray-400 font-medium max-w-[180px]">鼠标悬停或点击卡片以快速预览稻米详情</p>
      </div>
    );
  }

  return (
    <div className="h-full bg-white rounded-3xl border border-gray-100 shadow-xl overflow-hidden flex flex-col animate-in slide-in-from-right-4 duration-300">
      <div className="relative aspect-video bg-gray-50 overflow-hidden">
        <img src={product.images?.[0] || product.packagingImage} alt={product.name} className="w-full h-full object-cover" />
        <div className="absolute top-4 right-4 flex gap-2">
          <button 
            onClick={() => onToggleFavorite(product.id)}
            className={`p-2 rounded-full shadow-lg backdrop-blur-md transition-all ${isFavorite ? 'bg-red-500 text-white' : 'bg-white/80 text-gray-400 hover:text-red-500'}`}
          >
            <Heart className={`w-4 h-4 ${isFavorite ? 'fill-current' : ''}`} />
          </button>
        </div>
        <div className="absolute bottom-0 left-0 right-0 bg-gradient-to-t from-black/60 to-transparent p-6 pt-12">
          <h3 className="text-white font-black text-lg leading-tight">{product.name}</h3>
        </div>
      </div>

      <div className="p-6 flex-1 overflow-y-auto custom-scrollbar space-y-6">
        <div className="flex items-center justify-between">
           <span className="text-2xl font-black text-emerald-600">¥{product.price}<span className="text-[10px] text-gray-400 font-bold uppercase ml-1">/kg</span></span>
           <div className="flex items-center gap-1.5 bg-blue-50 text-blue-600 px-3 py-1 rounded-full text-[10px] font-black uppercase">
              <Droplets className="w-3 h-3" /> 比 {product.cookingRatio}
           </div>
        </div>

        <div className="grid grid-cols-2 gap-3">
          <div className="bg-gray-50 p-3 rounded-2xl flex items-center gap-2 border border-gray-100">
            <MapPin className="w-3.5 h-3.5 text-emerald-500" />
            <span className="text-[11px] font-bold text-gray-700 truncate">{product.origin}</span>
          </div>
          <div className="bg-gray-50 p-3 rounded-2xl flex items-center gap-2 border border-gray-100">
            <Scale className="w-3.5 h-3.5 text-emerald-500" />
            <span className="text-[11px] font-bold text-gray-700">{product.weight}kg</span>
          </div>
        </div>

        <div className="space-y-2">
          <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">专家评语</h4>
          <p className="text-xs text-gray-600 leading-relaxed font-medium bg-emerald-50/30 p-4 rounded-2xl border border-emerald-100/30 italic">
             “{product.matchReason || product.description?.slice(0, 100) + '...'}”
          </p>
        </div>

        <div className="space-y-3">
           <h4 className="text-[10px] font-black text-gray-400 uppercase tracking-widest">属性图谱</h4>
           <div className="space-y-2">
              <div className="flex items-center justify-between">
                 <span className="text-[10px] font-bold text-gray-500">软糯度</span>
                 <span className="text-[10px] font-black text-emerald-600">{product.textureScore}%</span>
              </div>
              <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
                 <div className="h-full bg-emerald-500 transition-all duration-1000" style={{ width: `${product.textureScore}%` }}></div>
              </div>
           </div>
           <div className="space-y-2">
              <div className="flex items-center justify-between">
                 <span className="text-[10px] font-bold text-gray-500">米香浓度</span>
                 <span className="text-[10px] font-black text-amber-500">{product.aromaScore}%</span>
              </div>
              <div className="w-full h-1.5 bg-gray-100 rounded-full overflow-hidden">
                 <div className="h-full bg-amber-500 transition-all duration-1000" style={{ width: `${product.aromaScore}%` }}></div>
              </div>
           </div>
        </div>
      </div>

      <div className="p-6 border-t border-gray-100">
        <button className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-200 active:scale-95">
           立即查看更多
        </button>
      </div>
    </div>
  );
};

const App: React.FC = () => {
  const [userRole, setUserRole] = useState<UserRole>(null);
  const [currentUser, setCurrentUser] = useState<UserProfile | null>(null);
  const [inventory, setInventory] = useState<RiceProduct[]>([]);
  const [users, setUsers] = useState<UserProfile[]>([]);
  const [isLoading, setIsLoading] = useState(false);
  const [isDataFetching, setIsDataFetching] = useState(true);
  const [results, setResults] = useState<RecommendationResponse | null>(null);
  const [error, setError] = useState<string | null>(null);
  const [showAuthModal, setShowAuthModal] = useState(false);
  const [authConfig, setAuthConfig] = useState<{mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin'}>({mode: 'login', role: 'User'});
  const [viewMode, setViewMode] = useState<'search' | 'favorites'>('search');
  const [previewProduct, setPreviewProduct] = useState<RiceProduct | null>(null);

  useEffect(() => {
    const initApp = async () => {
      try {
        const [products, allUsers] = await Promise.all([
          RiceApi.fetchProducts(),
          RiceApi.fetchUsers()
        ]);
        setInventory(products);
        setUsers(allUsers);
      } catch (err) {
        setError("系统服务连接异常");
      } finally {
        setIsDataFetching(false);
      }
    };
    initApp();
  }, []);

  const handleLoginPortal = (role: UserRole) => {
    setUserRole(role);
    setResults(null); 
    setViewMode('search');
    if (role === 'user' || !role) {
      setCurrentUser(null);
    }
  };

  const handleOpenAuth = (mode: 'login' | 'register', role: 'User' | 'Merchant' | 'Admin') => {
      setAuthConfig({ mode, role });
      setShowAuthModal(true);
  };

  const handleLogout = () => {
    setUserRole(null);
    setResults(null);
    setCurrentUser(null);
    setViewMode('search');
  };

  const handleAddProduct = async (newProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(newProduct);
    setInventory(prev => [saved, ...prev.filter(p => p.id !== saved.id)]);
  };

  const handleUpdateProduct = async (updatedProduct: RiceProduct) => {
    const saved = await RiceApi.saveProduct(updatedProduct);
    setInventory(prev => prev.map(p => p.id === saved.id ? saved : p));
  };

  const handleUpdateUsers = (updatedUsers: UserProfile[]) => setUsers(updatedUsers);

  const handleClientRegister = async (username: string, password?: string, role: 'User' | 'Merchant' | 'Admin' = 'User') => {
    const newUser: UserProfile = {
      id: `${role === 'Merchant' ? 'M' : role === 'Admin' ? 'A' : 'U'}${Date.now()}`,
      username, password, role, status: 'Active',
      ip: '127.0.0.1', lastActive: '刚刚', requestCount: 0, favorites: []
    };
    const registered = await RiceApi.register(newUser);
    const allUsers = await RiceApi.fetchUsers();
    setUsers(allUsers);
    setCurrentUser(registered);
    setUserRole(role === 'Merchant' ? 'merchant' : role === 'Admin' ? 'admin' : 'user');
    setShowAuthModal(false);
  };

  const handleClientLogin = async (username: string, password?: string) => {
    const allUsers = await RiceApi.fetchUsers();
    const user = allUsers.find(u => u.username === username && u.password === password);
    if (!user) throw new Error("账户名或密码错误，请检查输入。");
    if (user.status !== 'Active') throw new Error("该账号已被系统冻结，请联系管理员。");

    const updatedUser = { ...user, lastActive: '刚刚' };
    const mappedRole: UserRole = 
      user.role === 'Admin' ? 'admin' : 
      user.role === 'Merchant' ? 'merchant' : 'user';

    await RiceApi.syncUser(updatedUser);
    setUsers(allUsers.map(u => u.id === user.id ? updatedUser : u));
    setCurrentUser(updatedUser);
    setUserRole(mappedRole);
    setShowAuthModal(false);
  };

  const toggleFavorite = async (productId: string) => {
    if (!currentUser) return handleOpenAuth('login', 'User');
    const isFav = currentUser.favorites.includes(productId);
    const updatedUser = {
        ...currentUser,
        favorites: isFav ? currentUser.favorites.filter(id => id !== productId) : [...currentUser.favorites, productId]
    };
    setCurrentUser(updatedUser);
    setUsers(prev => prev.map(u => u.id === updatedUser.id ? updatedUser : u));
    await RiceApi.syncUser(updatedUser);
  };

  const handlePreferenceSubmit = async (prefs: UserPreferences) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.getRecommendations(prefs);
      setResults(data);
    } catch (err) {
      setError("匹配服务超时");
    } finally {
      setIsLoading(false);
    }
  };

  const handleImageSubmit = async (base64: string) => {
    setIsLoading(true);
    setError(null);
    try {
      const data = await RiceApi.analyzeImage(base64);
      setResults(data);
    } catch (err) {
      setError("AI分析暂时不可用");
    } finally {
      setIsLoading(false);
    }
  }

  const handleProductHover = (product: RiceProduct | null) => {
    setPreviewProduct(product);
  }

  if (isDataFetching) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gray-50">
        <div className="text-center animate-in fade-in zoom-in duration-500">
          <Loader2 className="w-10 h-10 animate-spin text-emerald-500 mx-auto mb-4" />
          <p className="text-xs font-black text-gray-400 uppercase tracking-[0.2em]">RiceHub System Loading</p>
        </div>
      </div>
    );
  }

  if (!userRole) return <Login onLogin={handleLoginPortal} onOpenAuth={handleOpenAuth} />;

  if (userRole === 'merchant' || userRole === 'admin') {
    return <AdminDashboard onLogout={handleLogout} inventory={inventory} onAddProduct={handleAddProduct} onUpdateProduct={handleUpdateProduct} users={users} onUpdateUsers={handleUpdateUsers} currentUser={currentUser} />;
  }

  return (
    <div className="min-h-screen bg-[#F8FAFC] flex text-gray-900 overflow-hidden font-sans">
      {/* 1. Left Sidebar Navigation */}
      <aside className="w-[260px] bg-white border-r border-gray-100 flex flex-col h-screen flex-shrink-0 z-50">
        <div className="p-8 pb-12">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 bg-emerald-600 rounded-xl flex items-center justify-center shadow-lg shadow-emerald-200">
              <Sprout className="w-6 h-6 text-white" />
            </div>
            <div className="flex flex-col">
              <h1 className="font-black text-xl tracking-tight leading-none italic">RICE<span className="text-emerald-600">HUB</span></h1>
              <span className="text-[9px] font-black text-gray-300 uppercase tracking-widest mt-1">v2.5 Dashboard</span>
            </div>
          </div>
        </div>

        <nav className="flex-1 px-4 space-y-2">
          <div className="text-[10px] font-black text-gray-400 uppercase tracking-widest ml-4 mb-4">主菜单</div>
          <NavItem icon={Compass} label="智能探索" active={viewMode === 'search'} onClick={() => setViewMode('search')} />
          <NavItem icon={Heart} label="我的收藏" active={viewMode === 'favorites'} onClick={() => setViewMode('favorites')} />
          <NavItem icon={Sparkles} label="每日推荐" active={false} onClick={() => {}} />
          <NavItem icon={History} label="搜索历史" active={false} onClick={() => {}} />
        </nav>

        <div className="p-4 mt-auto">
          <div className="bg-emerald-50 rounded-2xl p-4 border border-emerald-100 mb-4">
            <div className="flex items-center gap-2 mb-2">
              <Sparkles className="w-3.5 h-3.5 text-emerald-600" />
              <span className="text-[10px] font-black text-emerald-700 uppercase">Premium</span>
            </div>
            <p className="text-[10px] text-emerald-800 leading-relaxed font-medium">解锁专属风味图谱与高级分析。</p>
          </div>

          <button onClick={handleLogout} className="w-full flex items-center gap-3 px-4 py-3 text-gray-400 hover:text-red-500 hover:bg-red-50 rounded-xl transition-all font-bold text-sm">
            <LogOut className="w-4 h-4" /> 退出登录
          </button>
        </div>
      </aside>

      {/* 2. Main Workspace */}
      <main className="flex-1 flex flex-col h-screen overflow-hidden min-w-0">
        <header className="h-20 bg-white/50 backdrop-blur-md border-b border-gray-100 flex items-center justify-between px-8 flex-shrink-0">
           <div className="flex items-center gap-4">
              <div className="bg-gray-100 px-4 py-2 rounded-full flex items-center gap-2">
                <Search className="w-4 h-4 text-gray-400" />
                <input type="text" placeholder="寻找优质米源..." className="bg-transparent border-none text-sm focus:ring-0 w-64 placeholder:text-gray-400 font-medium" />
              </div>
           </div>

           <div className="flex items-center gap-6">
              <button className="relative text-gray-400 hover:text-gray-600">
                <Bell className="w-5 h-5" />
                <span className="absolute -top-1 -right-1 w-2 h-2 bg-red-500 rounded-full border-2 border-white"></span>
              </button>
              {currentUser ? (
                <div className="flex items-center gap-3">
                  <div className="text-right">
                    <p className="text-xs font-black text-gray-900 leading-none">{currentUser.username}</p>
                    <p className="text-[9px] font-bold text-gray-400 uppercase mt-1">正式会员</p>
                  </div>
                  <div className="w-10 h-10 rounded-2xl bg-emerald-50 border border-emerald-100 flex items-center justify-center text-emerald-600 font-black text-sm">
                    {currentUser.username.charAt(0).toUpperCase()}
                  </div>
                </div>
              ) : (
                <button onClick={() => handleOpenAuth('login', 'User')} className="text-xs font-black text-emerald-600 hover:text-emerald-700 underline underline-offset-4">立即登录</button>
              )}
           </div>
        </header>

        <div className="flex-1 overflow-y-auto custom-scrollbar p-8">
           {viewMode === 'search' ? (
             <div className="max-w-5xl mx-auto space-y-10">
                {!results ? (
                  <div className="flex flex-col items-center justify-center min-h-[60vh] animate-in fade-in slide-in-from-bottom-4 duration-700">
                    <div className="max-w-xl w-full">
                       <div className="text-center mb-10">
                          <h2 className="text-4xl font-black text-gray-900 tracking-tight mb-4">寻找最适合您的那一碗饭</h2>
                          <p className="text-gray-400 text-lg font-medium">多模态特征融合技术，为您精准匹配</p>
                       </div>
                       <PreferenceForm onSubmitPreferences={handlePreferenceSubmit} onSubmitImage={handleImageSubmit} isLoading={isLoading} />
                    </div>
                  </div>
                ) : (
                  <div className="space-y-8 animate-in fade-in slide-in-from-bottom-8 duration-700">
                    <div className="flex items-center justify-between">
                       <div>
                          <h2 className="text-2xl font-black text-gray-900">智能匹配结果</h2>
                          <p className="text-sm text-gray-500 font-medium mt-1">发现 {results.recommendations.length} 款符合您口味的稻米</p>
                       </div>
                       <button onClick={() => setResults(null)} className="flex items-center gap-2 px-5 py-2.5 bg-white border border-gray-100 rounded-xl text-xs font-black text-gray-500 hover:text-emerald-600 hover:border-emerald-100 transition-all shadow-sm">
                          <RotateCcw className="w-3.5 h-3.5" /> 重新匹配
                       </button>
                    </div>
                    <AnalysisChart products={results.recommendations} />
                    <ResultsGrid 
                      products={results.recommendations} 
                      analysisText={results.analysis} 
                      favorites={currentUser?.favorites || []} 
                      onToggleFavorite={toggleFavorite} 
                      onProductHover={handleProductHover}
                    />
                  </div>
                )}
             </div>
           ) : (
             <div className="max-w-6xl mx-auto animate-in fade-in duration-500">
                <div className="mb-10">
                   <h2 className="text-3xl font-black text-gray-900">我的收藏库</h2>
                   <p className="text-gray-500 font-medium mt-1">整理并管理您最钟爱的稻米品种</p>
                </div>
                <ResultsGrid 
                  products={inventory.filter(p => currentUser?.favorites.includes(p.id))} 
                  analysisText="" 
                  favorites={currentUser?.favorites || []} 
                  onToggleFavorite={toggleFavorite} 
                  showAnalysis={false} 
                  onProductHover={handleProductHover}
                />
             </div>
           )}
        </div>
      </main>

      {/* 3. Right Preview Panel */}
      <aside className="w-[340px] bg-gray-50/50 p-6 h-screen flex-shrink-0 z-40 hidden xl:block border-l border-gray-100">
        <PreviewPanel 
          product={previewProduct} 
          isFavorite={!!previewProduct && (currentUser?.favorites.includes(previewProduct.id) || false)}
          onToggleFavorite={toggleFavorite}
        />
      </aside>

      {showAuthModal && (
        <UserAuthModal 
            initialMode={authConfig.mode}
            initialRole={authConfig.role}
            onClose={() => setShowAuthModal(false)} 
            onLogin={handleClientLogin} 
            onRegister={handleClientRegister} 
        />
      )}
    </div>
  );
};

export default App;

import React, { useState } from 'react';
import { RiceProduct } from '../types';
import { MapPin, ChevronRight, Package, X, Scale, Image as ImageIcon, Sparkles, Heart, Droplets, ExternalLink, ChevronLeft } from 'lucide-react';

interface ResultsGridProps {
  products: RiceProduct[];
  analysisText: string;
  favorites?: string[];
  onToggleFavorite?: (id: string) => void;
  showAnalysis?: boolean;
  onProductHover?: (product: RiceProduct | null) => void;
}

interface ProductDetailModalProps {
  product: RiceProduct;
  onClose: () => void;
  isFavorite?: boolean;
  onToggleFavorite?: (id: string) => void;
  accentColor: string;
}

export const ProductDetailModal: React.FC<ProductDetailModalProps> = ({ product, onClose, isFavorite, onToggleFavorite, accentColor }) => {
  const images = product.images && product.images.length > 0 ? product.images : (product.packagingImage ? [product.packagingImage] : []);
  const [currentImgIdx, setCurrentImgIdx] = useState(0);

  const nextImg = () => setCurrentImgIdx((prev) => (prev + 1) % images.length);
  const prevImg = () => setCurrentImgIdx((prev) => (prev - 1 + images.length) % images.length);

  return (
    <div className="fixed inset-0 z-[200] flex items-center justify-center p-4 bg-black/60 backdrop-blur-sm animate-in fade-in duration-300">
      <div className="bg-white rounded-3xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col relative animate-in zoom-in-95 duration-300">

        <div className="flex justify-between items-center px-6 py-4 border-b border-gray-100 bg-white/80 backdrop-blur-md sticky top-0 z-30">
           <div className="flex flex-col min-w-0 pr-4">
              <h2 className="text-xl font-bold text-gray-900 truncate leading-tight">{product.name}</h2>
           </div>
           <div className="flex items-center gap-2 flex-shrink-0">
              {onToggleFavorite && (
                <button 
                  onClick={(e) => { e.stopPropagation(); onToggleFavorite(product.id); }} 
                  className={`p-2.5 rounded-full transition-all ${isFavorite ? 'bg-red-50 text-red-500' : 'bg-gray-50 text-gray-300 hover:text-gray-400'}`}
                >
                  <Heart className={`w-5 h-5 ${isFavorite ? 'fill-current' : ''}`} />
                </button>
              )}
              <button 
                onClick={onClose} 
                className="p-2.5 text-gray-400 hover:text-gray-900 bg-gray-50 rounded-full transition-colors"
              >
                <X className="w-5 h-5" />
              </button>
           </div>
        </div>

        <div className="overflow-y-auto flex-1 custom-scrollbar">
          <div className="flex flex-col lg:flex-row h-full">
            {/* Image Gallery */}
            <div className="w-full lg:w-1/2 bg-gray-50 flex flex-col items-center justify-center p-6 min-h-[350px] relative group border-r border-gray-50">
               <div className={`absolute top-0 left-0 w-full h-1.5 ${accentColor}`}></div>

               <div className="relative w-full aspect-square flex items-center justify-center bg-white rounded-2xl overflow-hidden shadow-inner border border-gray-100">
                  {images.length > 0 ? (
                      <>
                        <img src={images[currentImgIdx]} alt={product.name} className="w-full h-full object-contain transition-all duration-500" />
                        {images.length > 1 && (
                            <>
                                <button onClick={prevImg} className="absolute left-2 top-1/2 -translate-y-1/2 p-2 bg-black/10 hover:bg-black/20 text-white rounded-full transition-all backdrop-blur-sm">
                                    <ChevronLeft className="w-6 h-6" />
                                </button>
                                <button onClick={nextImg} className="absolute right-2 top-1/2 -translate-y-1/2 p-2 bg-black/10 hover:bg-black/20 text-white rounded-full transition-all backdrop-blur-sm">
                                    <ChevronRight className="w-6 h-6" />
                                </button>
                            </>
                        )}
                      </>
                  ) : (
                    <div className="flex flex-col items-center text-gray-200">
                        <ImageIcon className="w-16 h-16 mb-2" />
                        <span className="text-xs font-bold uppercase tracking-widest">No Image</span>
                    </div>
                  )}
               </div>

               {images.length > 1 && (
                   <div className="flex gap-2 mt-4 overflow-x-auto w-full py-2 custom-scrollbar">
                       {images.map((img, i) => (
                           <button 
                                key={i} 
                                onClick={() => setCurrentImgIdx(i)}
                                className={`flex-shrink-0 w-16 h-16 rounded-lg border-2 overflow-hidden transition-all ${i === currentImgIdx ? 'border-emerald-500' : 'border-transparent opacity-60 hover:opacity-100'}`}
                           >
                               <img src={img} alt="" className="w-full h-full object-cover" />
                           </button>
                       ))}
                   </div>
               )}
            </div>

            <div className="w-full lg:w-1/2 p-8 space-y-6 flex flex-col">
               <div className="flex items-center text-sm text-gray-500 gap-6">
                  <div className="flex items-center"><MapPin className="w-4 h-4 mr-1.5 text-emerald-500" /> {product.origin}</div>
                  <div className="flex items-center"><Scale className="w-4 h-4 mr-1.5 text-emerald-500" /> {product.weight}kg</div>
                  <div className="ml-auto text-2xl font-black text-emerald-600">¥{product.price}<span className="text-xs font-normal text-gray-400">/kg</span></div>
               </div>

               <div className="bg-blue-50/50 p-4 rounded-2xl border border-blue-100 flex items-center justify-between">
                  <div className="flex items-center gap-3">
                     <div className="p-2.5 bg-blue-500 rounded-xl text-white shadow-lg shadow-blue-100">
                        <Droplets className="w-5 h-5" />
                     </div>
                     <div>
                        <h4 className="text-[10px] font-black text-blue-600 uppercase tracking-widest">最佳推荐米水比</h4>
                        <div className="text-xl font-black text-blue-900 leading-none mt-1">{product.cookingRatio}</div>
                     </div>
                  </div>
                  <div className="text-[10px] text-blue-400 font-bold text-right leading-tight max-w-[100px]">
                     建议搭配软质纯净水
                  </div>
               </div>

               <div className="bg-emerald-50/80 p-5 rounded-2xl border border-emerald-100/50">
                  <h4 className="text-xs font-black text-emerald-800 uppercase tracking-widest mb-2 flex items-center gap-2">
                    <Sparkles className="w-3.5 h-3.5 text-amber-500" /> 智能融合匹配算法
                  </h4>
                  <p className="text-sm text-emerald-900 leading-relaxed font-bold">
                    {product.matchReason || "深度符合您的多维度历史偏好，推荐度 98%。"}
                  </p>
               </div>

               <div className="space-y-3">
                  <h4 className="text-xs font-black text-gray-900 uppercase tracking-widest">产品风味描述</h4>
                  <p className="text-sm text-gray-500 leading-relaxed border-l-4 border-emerald-100 pl-4">
                    {product.description}
                  </p>
               </div>

               <div className="flex-1 min-h-[40px]"></div>

               <div className="pt-6 border-t border-gray-100 flex flex-col gap-4">
                  {product.purchaseUrl && (
                      <a 
                        href={product.purchaseUrl} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="w-full bg-emerald-600 text-white py-4 rounded-2xl font-black uppercase tracking-widest flex items-center justify-center gap-2 hover:bg-emerald-700 transition-all shadow-xl shadow-emerald-100 active:scale-95"
                      >
                        <ExternalLink className="w-5 h-5" />
                        立即下单购买
                      </a>
                  )}
               </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

const ProductCard: React.FC<{ product: RiceProduct; index: number; onClick: () => void; onHover?: (p: RiceProduct | null) => void }> = ({ product, index, onClick, onHover }) => {
    const accentColors = ['bg-emerald-500', 'bg-sky-500', 'bg-amber-500'];
    const accentColor = accentColors[index % 3];

    return (
        <div 
          onClick={onClick} 
          onMouseEnter={() => onHover?.(product)}
          className="group bg-white rounded-2xl border border-gray-200 hover:border-emerald-500 hover:shadow-2xl transition-all duration-500 flex flex-col h-full cursor-pointer overflow-hidden relative animate-in fade-in slide-in-from-bottom-4"
        >
            <div className={`h-1.5 w-full ${accentColor}`}></div>
            <div className="p-6 flex-1 flex flex-col">
                <div className="flex justify-between items-start mb-4">
                    <h3 className="text-gray-900 font-black text-lg leading-tight group-hover:text-emerald-700 transition-colors line-clamp-2">{product.name}</h3>
                    <div className="text-right flex-shrink-0">
                      <span className="text-xl font-black text-emerald-600">¥{product.price}</span>
                      <div className="text-[10px] text-gray-400 font-bold uppercase">/kg</div>
                    </div>
                </div>
                <div className="flex items-center gap-3 text-[11px] text-gray-400 mb-5 font-bold uppercase tracking-tighter">
                    <span className="flex items-center"><MapPin className="w-3.5 h-3.5 mr-1 text-emerald-500" />{product.origin.slice(0,5)}</span>
                    <span className="flex items-center"><Package className="w-3.5 h-3.5 mr-1 text-emerald-500" />{product.weight}kg</span>
                    <span className="flex items-center text-blue-500 font-black ml-auto bg-blue-50 px-2 py-0.5 rounded-md"><Droplets className="w-3 h-3 mr-1" />{product.cookingRatio}</span>
                </div>
                <div className="bg-gray-50/80 rounded-2xl p-4 mb-6 border border-gray-100 flex-1">
                    <p className="text-gray-600 text-xs leading-relaxed line-clamp-3 font-medium italic">
                        {product.matchReason || product.description}
                    </p>
                </div>
                <div className="pt-4 border-t border-gray-50 flex items-center justify-between">
                    <div className="flex -space-x-2">
                        {product.images?.slice(0, 3).map((img, i) => (
                            <div key={i} className="w-7 h-7 rounded-full border-2 border-white bg-gray-100 overflow-hidden shadow-sm">
                                <img src={img} alt="" className="w-full h-full object-cover" />
                            </div>
                        ))}
                    </div>
                    <span className="text-xs font-black text-emerald-600 flex items-center gap-1 group-hover:gap-2 transition-all">
                        详情探索 <ChevronRight className="w-4 h-4" />
                    </span>
                </div>
            </div>
        </div>
    );
};

const ResultsGrid: React.FC<ResultsGridProps> = ({ products, analysisText, favorites = [], onToggleFavorite, showAnalysis = true, onProductHover }) => {
  const [selectedProduct, setSelectedProduct] = useState<RiceProduct | null>(null);

  return (
    <div className="space-y-6">
      {showAnalysis && analysisText && (
        <div className="bg-white p-6 rounded-2xl border border-emerald-100 shadow-sm relative overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500">
           <div className="absolute top-0 left-0 w-1.5 h-full bg-emerald-500"></div>
           <h3 className="text-xs font-black text-emerald-800 uppercase tracking-widest mb-3 flex items-center gap-2">
              <Sparkles className="w-4 h-4 text-amber-500" /> AI 匹配分析报告
           </h3>
           <p className="text-gray-600 text-sm leading-relaxed font-medium">{analysisText}</p>
        </div>
      )}

      {products.length === 0 ? (
        <div className="text-center py-24 bg-white rounded-3xl border-2 border-dashed border-gray-100">
           <ImageIcon className="w-12 h-12 text-gray-200 mx-auto mb-4" />
           <p className="text-gray-400 text-sm font-bold uppercase tracking-widest">No Products Found</p>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-6">
          {products.map((product, index) => (
               <ProductCard 
                  key={product.id} 
                  product={product} 
                  index={index} 
                  onClick={() => setSelectedProduct(product)} 
                  onHover={onProductHover}
               />
          ))}
        </div>
      )}

      {selectedProduct && (
          <ProductDetailModal 
            product={selectedProduct} 
            onClose={() => setSelectedProduct(null)} 
            isFavorite={favorites.includes(selectedProduct.id)}
            onToggleFavorite={onToggleFavorite}
            accentColor="bg-emerald-500"
          />
      )}
    </div>
  );
};

export default ResultsGrid;
